const GLOSS=[{'t':'QAIR — Qualité de l\'air intérieur','d':'Thème évaluant la qualité de l\'air à l\'intérieur des bâtiments. Il couvre la maîtrise des sources de pollution (matériaux, activités), la ventilation, le suivi des concentrations de polluants (COV, formaldéhyde, particules fines, radon) et la sensibilisation des occupants.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'QEAU — Qualité de l\'eau','d':'Thème relatif à la préservation de la qualité sanitaire de l\'eau dans les réseaux intérieurs du bâtiment. Il traite de la conception, de l\'entretien et du suivi des installations pour prévenir les risques liés aux légionelles, au plomb, aux bras morts et à la stagnation.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'ONDE — Ondes électromagnétiques','d':'Thème visant à limiter l\'exposition des occupants aux champs électromagnétiques basse et haute fréquence. Il évalue les niveaux d\'émission des équipements, des réseaux internes (Wi-Fi, CPL) et des sources extérieures (antennes relais).','c':'THÈMES DE CERTIFICATION HQE'},{'t':'HYGR — Confort hygrothermique','d':'Thème évaluant les conditions de température et d\'humidité dans les espaces intérieurs. Il prend en compte la conception bioclimatique, la régulation thermique, la gestion des surchauffes estivales et le confort ressenti par les occupants.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'ACOU — Confort acoustique','d':'Thème mesurant la performance acoustique du bâtiment : isolement aux bruits aériens extérieurs et intérieurs, bruits d\'impact, bruits d\'équipements, temps de réverbération et niveau de bruit de fond dans les locaux.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'VISU — Confort visuel','d':'Thème relatif à l\'éclairage naturel et artificiel des espaces. Il évalue l\'accès à la lumière du jour (Facteur de Lumière du Jour), l\'accès aux vues extérieures, la maîtrise de l\'éblouissement et l\'uniformité de l\'éclairement.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'ACES — Accessibilité','d':'Thème évaluant l\'accessibilité du bâtiment et de ses abords pour tous les usagers, y compris les personnes à mobilité réduite (PMR). Il couvre les circulations extérieures, le stationnement adapté, la signalétique et les équipements d\'usage.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'TRAN — Transports','d':'Thème relatif à la desserte du bâtiment en transports en commun, aux infrastructures pour la mobilité douce (vélo, marche), aux bornes de recharge pour véhicules électriques et à la promotion du covoiturage et de l\'autopartage.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'SERV — Services','d':'Thème évaluant la qualité et la diversité des services proposés aux occupants du bâtiment : restauration, conciergerie, espaces de convivialité, signalétique, accueil, gestion des livraisons, etc.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'ENER — Énergie','d':'Thème central de la performance énergétique du bâtiment. Il couvre la consommation d\'énergie primaire (Cep), le besoin bioclimatique (Bbio), la production d\'énergie renouvelable, le sous-comptage, la GTB et la gestion active de l\'énergie.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'EAU — Eau','d':'Thème relatif à la gestion quantitative de la ressource en eau : suivi des consommations, équipements hydro-économes, récupération des eaux de pluie, gestion des eaux pluviales à la parcelle et réduction des rejets.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'DECH — Déchets','d':'Thème couvrant la gestion des déchets d\'activité et de chantier : tri sélectif, valorisation matière et énergétique, filières de traitement, traçabilité (bordereaux de suivi), et réduction à la source.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'CARB — Carbone','d':'Thème évaluant les émissions de gaz à effet de serre du bâtiment en exploitation. Il mesure les émissions liées à l\'énergie consommée (kgCO₂eq/m².an) et celles liées aux déplacements des usagers.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'ACCL — Adaptation au changement climatique','d':'Thème qui analyse la vulnérabilité du bâtiment face aux aléas climatiques (canicules, inondations, tempêtes, sécheresses) et les mesures d\'adaptation mises en œuvre pour assurer sa résilience.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'ACV — Impacts environnementaux sur le cycle de vie','d':'Thème mesurant les impacts environnementaux du bâtiment sur l\'ensemble de son cycle de vie (construction, exploitation, fin de vie) selon la norme EN 15978 : changement climatique, épuisement des ressources, pollution de l\'eau, etc.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'BIOD — Biodiversité','d':'Thème évaluant la prise en compte de la biodiversité : diagnostic écologique initial, coefficient de biotope (CBS), connectivité écologique, gestion différenciée des espaces verts et préservation des espèces protégées.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'COUT — Maîtrise des coûts','d':'Thème relatif à l\'optimisation du coût global du bâtiment sur son cycle de vie : investissement initial, coûts d\'exploitation, de maintenance, d\'énergie et de fin de vie, en favorisant les choix les plus économiquement durables.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'DEVT — Économie locale','d':'Thème encourageant le recours aux entreprises, matériaux et ressources locales lors de la construction et de l\'exploitation, afin de dynamiser le tissu économique du territoire.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'ADAP — Adaptabilité','d':'Thème évaluant la capacité du bâtiment à évoluer dans le temps : flexibilité des espaces, réversibilité des aménagements, démontabilité des composants, anticipation des changements d\'usage et des évolutions techniques.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'CHAN — Chantier','d':'Thème relatif à la gestion environnementale du chantier de construction ou de rénovation : réduction des nuisances (bruit, poussière), gestion des déchets de chantier, préservation du site et de son voisinage.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'COMM — Commissionnement','d':'Thème évaluant la mise en œuvre d\'une démarche de commissionnement pour vérifier que les systèmes techniques du bâtiment fonctionnent conformément aux objectifs de performance définis par la maîtrise d\'ouvrage.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'GD — Gestion Durable','d':'Thème transversal portant sur l\'exploitation durable du bâtiment. Il couvre le pilotage de la performance (énergie, eau, déchets, QAI), la maintenance des équipements, le suivi des indicateurs et l\'amélioration continue en phase d\'exploitation.','c':'THÈMES DE CERTIFICATION HQE'},{'t':'Adaptation au changement climatique','d':'Ensemble des stratégies et actions visant à réduire la vulnérabilité d\'un bâtiment face aux effets du changement climatique (vagues de chaleur, inondations, sécheresses, tempêtes) et à maintenir ses conditions de fonctionnement et de confort.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Albédo','d':'Rapport entre l\'énergie lumineuse réfléchie par une surface et l\'énergie lumineuse incidente. Un albédo élevé (surfaces claires) réduit l\'absorption de chaleur et limite l\'effet d\'îlot de chaleur urbain.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Aménagement durable','d':'Démarche de planification et de conception de l\'espace bâti et non bâti intégrant les dimensions environnementale, sociale et économique pour un développement équilibré du territoire.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Analyse du Cycle de Vie (ACV)','d':'Méthode normalisée (EN 15978 pour les bâtiments) permettant d\'évaluer les impacts environnementaux d\'un produit ou d\'un bâtiment sur l\'ensemble de son cycle de vie, de l\'extraction des matières premières à la fin de vie.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Annexe environnementale','d':'Document obligatoire (loi Grenelle II) annexé aux baux commerciaux de locaux de plus de 2 000 m², décrivant les caractéristiques énergétiques et environnementales du bâtiment et les engagements respectifs du bailleur et du preneur.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Approche Environnementale de l\'Urbanisme (AEU)','d':'Méthode développée par l\'ADEME pour intégrer les enjeux environnementaux (énergie, déplacements, eau, déchets, biodiversité, bruit) dans les projets d\'aménagement et les documents d\'urbanisme.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Bail vert','d':'Clause ou annexe environnementale intégrée au contrat de bail, engageant le bailleur et le locataire à améliorer la performance environnementale du bâtiment et à échanger les données de consommation.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Bassin de rétention','d':'Ouvrage de stockage temporaire des eaux pluviales permettant de réguler les débits de rejet vers le réseau ou le milieu naturel, en écrêtant les pointes de ruissellement lors des épisodes de pluie.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Bilan carbone','d':'Méthode développée par l\'ADEME pour comptabiliser les émissions de gaz à effet de serre directes et indirectes d\'une activité, d\'un bâtiment ou d\'un territoire, exprimées en tonnes équivalent CO₂.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Biodiversité','d':'Diversité du vivant à tous ses niveaux : diversité des espèces (faune, flore, micro-organismes), diversité génétique au sein des espèces et diversité des écosystèmes. En HQE, elle est évaluée à l\'échelle de la parcelle et de son insertion dans les continuités écologiques.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Bois construction','d':'Matériau de construction issu de la filière forestière, utilisé en structure, en parement ou en isolation. Sa mise en œuvre favorise le stockage de carbone biogénique et réduit l\'empreinte carbone du bâtiment.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Béton bas carbone','d':'Béton formulé pour réduire son empreinte carbone par rapport à un béton conventionnel, grâce à l\'utilisation de liants alternatifs (laitier, cendres volantes), de granulats recyclés ou de procédés de fabrication optimisés.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Changement climatique','d':'Modification durable du climat à l\'échelle planétaire, principalement due à l\'augmentation des concentrations de gaz à effet de serre d\'origine anthropique. Ses effets incluent l\'élévation des températures, la montée des eaux et l\'intensification des événements extrêmes.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Chantier propre','d':'Chantier de construction ou de rénovation géré selon des pratiques visant à réduire les nuisances sur l\'environnement et le voisinage : tri des déchets, limitation du bruit et des poussières, protection des sols et des eaux.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Chantier à faibles nuisances','d':'Synonyme de chantier propre, mettant l\'accent sur la réduction des nuisances sonores, visuelles, olfactives et liées au trafic pour les riverains et le milieu naturel environnant.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Coefficient de Biotope par Surface (CBS)','d':'Ratio entre la surface éco-aménageable favorable à la biodiversité (espaces verts, toitures végétalisées, surfaces perméables) et la surface totale de la parcelle. Plus le CBS est élevé, plus le terrain est favorable à la nature.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Coefficient de ruissellement','d':'Rapport entre le volume d\'eau ruisselé en surface et le volume total d\'eau précipité. Il dépend de la nature du sol et de son imperméabilisation. Un coefficient faible indique une bonne infiltration.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Continuité écologique','d':'Ensemble des milieux naturels permettant aux espèces animales et végétales de circuler, de se reproduire et d\'assurer leur cycle de vie, formant un réseau fonctionnel entre les réservoirs de biodiversité.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Corridor écologique','d':'Bande de terrain reliant deux réservoirs de biodiversité, permettant le déplacement des espèces. Il peut être terrestre (haie, boisement), aquatique (cours d\'eau) ou aérien (alignement d\'arbres).','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Diagnostic PEMD (Produits, Équipements, Matériaux, Déchets)','d':'Diagnostic obligatoire avant certaines démolitions ou rénovations significatives, identifiant les produits, équipements, matériaux et déchets présents dans le bâtiment afin de favoriser leur réemploi, recyclage ou valorisation.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Durabilité','d':'Capacité d\'un bâtiment, d\'un matériau ou d\'un système à maintenir ses performances et ses fonctions dans le temps, en tenant compte des contraintes d\'usage, d\'entretien et d\'évolution climatique.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Déclaration Environnementale de Produit (DEP / EPD)','d':'Document normalisé (EN 15804) présentant les résultats de l\'analyse de cycle de vie d\'un produit de construction, permettant de comparer objectivement les impacts environnementaux entre produits de même fonction.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Développement durable','d':'Mode de développement répondant aux besoins du présent sans compromettre la capacité des générations futures à satisfaire les leurs, selon les trois piliers : environnemental, social et économique (rapport Brundtland, 1987).','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Empreinte carbone','d':'Quantité totale de gaz à effet de serre émise directement ou indirectement par une activité, un produit ou un bâtiment, exprimée en équivalent CO₂.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Empreinte écologique','d':'Indicateur mesurant la surface de terre et d\'eau biologiquement productive nécessaire pour produire les ressources consommées et absorber les déchets générés par une activité ou une population.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Espèce protégée','d':'Espèce animale ou végétale bénéficiant d\'un statut de protection légale interdisant sa destruction, sa capture ou la dégradation de son habitat. Leur présence sur un site de projet impose des mesures d\'évitement ou de compensation.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Faune','d':'Ensemble des espèces animales présentes dans un écosystème donné. En HQE, l\'inventaire faunistique permet d\'évaluer la richesse écologique du site et d\'adapter le projet en conséquence.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Fiche de Déclaration Environnementale et Sanitaire (FDES)','d':'Document normalisé (NF EN 15804) établi par le fabricant d\'un produit de construction, détaillant ses impacts environnementaux sur tout son cycle de vie et ses caractéristiques sanitaires. Les FDES sont centralisées dans la base INIES.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Flore','d':'Ensemble des espèces végétales présentes dans un milieu donné. L\'inventaire floristique, réalisé dans le cadre du diagnostic écologique, permet d\'identifier les espèces remarquables ou protégées.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Gaz à Effet de Serre (GES)','d':'Gaz présents dans l\'atmosphère (CO₂, CH₄, N₂O, HFC, etc.) qui absorbent et réémettent le rayonnement infrarouge terrestre, contribuant au réchauffement climatique. Leur quantification est exprimée en kgCO₂ équivalent.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Gestion des eaux pluviales','d':'Ensemble des techniques (noues, bassins de rétention, tranchées drainantes, toitures végétalisées) permettant de collecter, stocker, infiltrer ou traiter les eaux de pluie à la parcelle afin de limiter le ruissellement et la pollution des milieux récepteurs.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Haute Qualité Environnementale (HQE)','d':'Démarche de certification des bâtiments développée en France, évaluant la performance environnementale sur de multiples critères : énergie, confort, santé, eau, déchets, biodiversité, carbone, accessibilité, etc. La version actuelle est HQE BD v4.1.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Impact carbone','d':'Quantité d\'émissions de gaz à effet de serre associée à un élément du bâtiment (composants, énergie, eau, chantier, parcelle), mesurée en kgCO₂eq selon la méthodologie RE2020 ou EN 15978.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Impact environnemental','d':'Toute modification de l\'environnement, négative ou bénéfique, résultant totalement ou partiellement des activités, produits ou services liés au bâtiment (pollution, épuisement des ressources, atteinte à la biodiversité, etc.).','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Imperméabilisation des sols','d':'Recouvrement du sol par des matériaux étanches (béton, bitume) empêchant l\'infiltration naturelle de l\'eau. Elle augmente le ruissellement, le risque d\'inondation et réduit la recharge des nappes phréatiques.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Indicateurs environnementaux','d':'Grandeurs mesurables permettant de quantifier les impacts environnementaux d\'un bâtiment : consommation d\'énergie, émissions de GES, consommation d\'eau, production de déchets, etc. Ils servent au suivi de la performance et à l\'amélioration continue.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Infiltration','d':'Processus par lequel l\'eau de pluie pénètre dans le sol. En gestion des eaux pluviales, les techniques d\'infiltration (noues, tranchées, sols perméables) permettent de restituer l\'eau au cycle naturel et de limiter le ruissellement.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Matériau biosourcé','d':'Matériau de construction issu de la biomasse végétale ou animale (bois, chanvre, paille, laine de mouton, ouate de cellulose). Son utilisation permet de stocker du carbone biogénique et de réduire l\'impact environnemental du bâtiment.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Mur végétalisé','d':'Paroi verticale recouverte de végétation, contribuant à l\'isolation thermique, à la biodiversité urbaine, à la gestion des eaux pluviales et à l\'amélioration du microclimat local par évapotranspiration.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Neutralité carbone','d':'État d\'équilibre entre les émissions de gaz à effet de serre produites et les quantités absorbées ou compensées, résultant en un bilan net nul. Objectif fixé par l\'Accord de Paris pour la seconde moitié du XXIe siècle.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'NF Environnement','d':'Écolabel officiel français, délivré par AFNOR Certification, attestant qu\'un produit présente un impact environnemental réduit tout en conservant une qualité d\'usage satisfaisante.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Nordic Swan','d':'Écolabel officiel des pays nordiques (Suède, Norvège, Danemark, Finlande, Islande), certifiant que les produits respectent des critères environnementaux stricts sur l\'ensemble de leur cycle de vie.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Noue','d':'Fossé peu profond, enherbé ou végétalisé, conçu pour collecter, stocker temporairement et infiltrer les eaux pluviales de ruissellement, tout en assurant un rôle paysager et de support à la biodiversité.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Objectifs de Développement Durable (ODD)','d':'Les 17 objectifs adoptés par les Nations Unies en 2015 dans le cadre de l\'Agenda 2030, couvrant les enjeux sociaux, économiques et environnementaux à l\'échelle mondiale (climat, eau, énergie, villes durables, etc.).','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Obsolescence','d':'Perte de valeur d\'un équipement ou d\'un composant du bâtiment due à l\'évolution technique, réglementaire ou des usages, avant même la fin de sa durée de vie physique. L\'adaptabilité du bâtiment vise à limiter ce phénomène.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Performance environnementale','d':'Résultat mesurable de la gestion des aspects environnementaux d\'un bâtiment par rapport à des objectifs définis. En HQE, elle est évaluée par des indicateurs quantitatifs dans chaque thème (énergie, carbone, eau, déchets, etc.).','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Potentiel de Réchauffement Global (PRG / GWP)','d':'Indicateur exprimant la contribution d\'un gaz à l\'effet de serre par rapport au CO₂ sur une période donnée (généralement 100 ans). Le CO₂ a un PRG de 1, le méthane environ 28, certains HFC dépassent 10 000.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Produit de construction','d':'Tout produit ou matériau fabriqué et mis sur le marché en vue d\'être incorporé de façon durable dans un ouvrage de construction. Soumis au marquage CE et pouvant faire l\'objet d\'une FDES ou d\'une DEP.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Pérennité','d':'Aptitude d\'un ouvrage ou d\'un équipement à conserver ses caractéristiques fonctionnelles et ses performances dans la durée, moyennant un entretien adapté.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Qualité Environnementale du Bâtiment (QEB)','d':'Ensemble des caractéristiques du bâtiment, de ses équipements et de la parcelle qui lui confèrent l\'aptitude à satisfaire les besoins de maîtrise des impacts environnementaux et de création de conditions de confort et de santé satisfaisantes.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Recyclage','d':'Opération de valorisation par laquelle les matériaux constituant un déchet sont retraités pour être réutilisés sous forme de matière première dans un nouveau cycle de production, réduisant ainsi la consommation de ressources naturelles.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Responsabilité Sociétale des Entreprises (RSE)','d':'Démarche volontaire d\'intégration des préoccupations sociales, environnementales et économiques dans les activités et les relations avec les parties prenantes d\'une entreprise.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Réemploi','d':'Opération par laquelle un produit ou un composant de construction est utilisé à nouveau pour un usage identique à celui pour lequel il avait été conçu, sans transformation majeure. Différent du recyclage qui implique une transformation.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Résilience climatique','d':'Capacité d\'un bâtiment ou d\'un territoire à anticiper, absorber et se remettre des perturbations liées au changement climatique tout en maintenant ses fonctions essentielles.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Rétention','d':'Stockage temporaire des eaux pluviales dans un ouvrage (bassin, cuve, toiture-terrasse) pour réguler leur restitution progressive vers le réseau ou le milieu naturel et éviter les surcharges en période de forte pluie.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Sobriété énergétique','d':'Démarche visant à réduire les consommations d\'énergie en agissant sur les comportements des usagers et l\'organisation des activités, avant même d\'optimiser l\'efficacité des systèmes techniques.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Système de Management de l\'Opération (SMO)','d':'Cadre organisationnel structurant la démarche HQE d\'un projet, définissant les objectifs environnementaux, les responsabilités, les moyens, le planning et les modalités de suivi et de vérification.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Toiture végétalisée','d':'Couverture de bâtiment recouverte d\'un substrat végétal, contribuant à la gestion des eaux pluviales (rétention), à l\'isolation thermique, à la biodiversité urbaine et à la réduction de l\'effet d\'îlot de chaleur.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Trame verte et bleue','d':'Réseau écologique national composé de continuités terrestres (trame verte) et aquatiques (trame bleue), visant à maintenir et restaurer les échanges entre les milieux naturels pour la survie des espèces.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Tranchée drainante','d':'Ouvrage linéaire rempli de matériaux drainants (graviers, galets), permettant de collecter et d\'infiltrer les eaux pluviales dans le sol, tout en jouant un rôle de filtre naturel.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Valorisation des déchets','d':'Ensemble des opérations de traitement permettant de tirer une valeur des déchets : valorisation matière (recyclage, réemploi), valorisation énergétique (incinération avec récupération d\'énergie) ou valorisation organique (compostage).','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'ZNIEFF (Zone Naturelle d\'Intérêt Écologique, Faunistique et Floristique)','d':'Inventaire scientifique national identifiant les secteurs présentant un intérêt écologique particulier. Les ZNIEFF de type I correspondent à des secteurs de grand intérêt biologique, les ZNIEFF de type II à de grands ensembles naturels riches.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Zone Natura 2000','d':'Réseau européen de sites naturels protégés, établi en application des directives Oiseaux et Habitats, visant à préserver la biodiversité sur le territoire de l\'Union européenne. Tout projet à proximité doit évaluer ses incidences.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Écolabel européen','d':'Label environnemental officiel de l\'Union européenne, identifiable par le logo en forme de fleur, certifiant que les produits ou services labellisés ont un impact environnemental réduit tout au long de leur cycle de vie.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Économie circulaire','d':'Modèle économique visant à produire des biens et services de manière durable en limitant la consommation de ressources et la production de déchets, par le réemploi, la réparation, le recyclage et la valorisation.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'Îlot de Chaleur Urbain (ICU)','d':'Phénomène d\'élévation de la température en zone urbaine par rapport aux zones rurales environnantes, causé par l\'absorption de chaleur par les matériaux de construction, la réduction de la végétation et les rejets de chaleur anthropiques.','c':'CONCEPTS ENVIRONNEMENTAUX ET DÉVELOPPEMENT DURABLE'},{'t':'ASI (Alimentation Sans Interruption)','d':'Équipement électrique garantissant la continuité de l\'alimentation en cas de coupure de courant, composé de batteries, d\'un onduleur et d\'un système de commutation automatique. Essentiel pour les locaux techniques sensibles (datacenters, serveurs).','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Audit énergétique','d':'Examen méthodique et documenté des consommations et des usages énergétiques d\'un bâtiment, aboutissant à des préconisations chiffrées d\'amélioration de la performance énergétique, avec estimation des coûts et des économies attendues.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Automate programmable','d':'Dispositif électronique de contrôle-commande gérant automatiquement le fonctionnement des équipements techniques du bâtiment (chauffage, ventilation, éclairage) selon des programmes et des consignes prédéfinis.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'BBC (Bâtiment Basse Consommation)','d':'Label attestant une consommation d\'énergie primaire inférieure à un seuil réglementaire (50 kWhEP/m².an modulé selon la zone climatique et l\'altitude pour le résidentiel). Introduit par le Grenelle de l\'Environnement.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Bbio (Besoin bioclimatique)','d':'Indicateur réglementaire (RE2020 et ex-RT2012) exprimant les besoins en énergie du bâtiment liés à la conception bioclimatique (chauffage, refroidissement, éclairage), indépendamment des systèmes installés. Plus le Bbio est bas, meilleure est la conception.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Bbiomax','d':'Valeur maximale réglementaire du Bbio, modulée selon la zone climatique, l\'altitude, la catégorie du bâtiment et sa surface. Le Bbio du projet doit être inférieur au Bbiomax pour être conforme.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'BEPOS (Bâtiment à Énergie POSitive)','d':'Bâtiment dont la production d\'énergie renouvelable sur site dépasse la consommation d\'énergie primaire sur une année. Objectif porté par le label E+C- et la réglementation RE2020.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'BILAN GES / BEGES','d':'Bilan des Émissions de Gaz à Effet de Serre, obligatoire pour certaines collectivités et entreprises. Il quantifie les émissions directes et indirectes d\'une organisation, d\'un territoire ou d\'un bâtiment en tCO₂eq.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Biogaz','d':'Gaz combustible produit par la fermentation anaérobie de matières organiques (déchets agricoles, boues d\'épuration, déchets alimentaires). Utilisable pour le chauffage, la cogénération ou l\'injection dans le réseau de gaz naturel.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Biomasse','d':'Ensemble des matières organiques d\'origine végétale ou animale pouvant être utilisées comme source d\'énergie renouvelable (bois-énergie, biocarburants, biogaz, cultures énergétiques).','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Capteur connecté','d':'Dispositif de mesure (température, humidité, CO₂, luminosité, présence) relié à un réseau de communication permettant la collecte et l\'analyse de données en temps réel pour le pilotage énergétique et le confort du bâtiment.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Cep,nr (énergie primaire non renouvelable)','d':'Indicateur réglementaire RE2020 exprimant la consommation d\'énergie primaire non renouvelable du bâtiment en kWhEP/m².an, pour les cinq usages réglementaires (chauffage, refroidissement, ECS, éclairage, auxiliaires).','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'CESI (Chauffe-Eau Solaire Individuel)','d':'Installation solaire thermique composée de capteurs solaires et d\'un ballon de stockage, permettant de produire de l\'eau chaude sanitaire grâce à l\'énergie solaire, couvrant généralement 50 à 70 % des besoins.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Coefficient de transmission thermique (Uw, Ucw, Up)','d':'Grandeur exprimant la quantité de chaleur traversant un élément de paroi par unité de surface et de différence de température (W/m².K). Uw pour les fenêtres, Ucw pour les murs-rideaux, Up pour les parois opaques. Plus la valeur est basse, meilleure est l\'isolation.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Cogénération','d':'Production simultanée d\'électricité et de chaleur à partir d\'une même source d\'énergie primaire, permettant d\'atteindre un rendement global élevé (70 à 90 %) par rapport à des productions séparées.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Consommation énergétique conventionnelle (Cep)','d':'Quantité d\'énergie primaire consommée par un bâtiment, calculée selon les méthodes réglementaires (RE2020, ex-RT2012), exprimée en kWhEP/m².an pour les cinq usages réglementaires.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Contrat de Performance Énergétique (CPE)','d':'Contrat entre un maître d\'ouvrage et un prestataire garantissant un niveau de performance énergétique mesurable, avec un engagement contractuel de réduction de consommation et un mécanisme de pénalités/bonus.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'COP (Coefficient de Performance)','d':'Rapport entre l\'énergie thermique produite (chauffage ou rafraîchissement) et l\'énergie électrique consommée par une pompe à chaleur. Un COP de 3 signifie que pour 1 kWh électrique consommé, 3 kWh de chaleur sont produits.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Datacenter / Salle serveur','d':'Local technique abritant des équipements informatiques à forte consommation énergétique, nécessitant une alimentation électrique sécurisée (ASI), un refroidissement dédié et un suivi de la performance énergétique (PUE).','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Degrés Jours Unifiés (DJU)','d':'Indicateur climatique mesurant l\'écart entre la température extérieure moyenne journalière et une température de référence (généralement 18°C). Utilisé pour estimer les besoins de chauffage et normaliser les consommations énergétiques.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'DPE (Diagnostic de Performance Énergétique)','d':'Document réglementaire obligatoire lors de la vente ou la location d\'un bien immobilier, classant le bâtiment de A à G en fonction de sa consommation d\'énergie primaire et de ses émissions de CO₂.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Débit de fuite','d':'Débit maximal d\'eau pluviale restitué par un ouvrage de rétention vers le réseau ou le milieu naturel, limité par la réglementation locale pour éviter les surcharges en aval.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'EER (Energy Efficiency Ratio)','d':'Rapport entre la puissance frigorifique fournie et la puissance électrique absorbée par un système de climatisation à un instant donné. Plus l\'EER est élevé, plus le système est efficace en mode froid.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Effacement énergétique','d':'Réduction temporaire et volontaire de la consommation électrique d\'un bâtiment en réponse à un signal du réseau électrique (pointe de demande, prix élevé), sans dégradation notable du service rendu.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Facteur solaire (Sw)','d':'Rapport entre l\'énergie solaire totale transmise à travers un vitrage et l\'énergie solaire incidente. Un facteur solaire faible limite les apports de chaleur en été (protections solaires), un facteur élevé favorise les apports gratuits en hiver.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Free cooling','d':'Technique de refroidissement passif utilisant directement l\'air extérieur frais (la nuit ou en mi-saison) pour rafraîchir les locaux, sans faire appel au groupe frigorifique, ce qui réduit la consommation énergétique de climatisation.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Groupe électrogène','d':'Installation de production d\'électricité de secours composée d\'un moteur thermique entraînant un alternateur, utilisée en cas de défaillance du réseau électrique pour maintenir en fonctionnement les équipements essentiels.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'GTB (Gestion Technique du Bâtiment)','d':'Système informatique centralisé permettant de superviser, contrôler et optimiser le fonctionnement des installations techniques du bâtiment (CVC, éclairage, contrôle d\'accès). Soumis au Décret BACS pour les bâtiments tertiaires.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'GTC (Gestion Technique Centralisée)','d':'Système de supervision regroupant la surveillance et le pilotage de l\'ensemble des lots techniques d\'un bâtiment ou d\'un patrimoine immobilier, permettant une vision globale et un historique des données de fonctionnement.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Géothermie','d':'Exploitation de la chaleur contenue dans le sous-sol terrestre pour le chauffage, le refroidissement ou la production d\'eau chaude sanitaire, via des sondes géothermiques couplées à des pompes à chaleur.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'IoT (Internet des Objets)','d':'Réseau de capteurs et d\'objets connectés communicant entre eux et avec des plateformes de gestion, permettant la collecte de données en temps réel pour le pilotage intelligent du bâtiment (énergie, confort, maintenance).','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'KNX','d':'Standard international de communication pour l\'automatisation des bâtiments (norme ISO/IEC 14543-3), permettant l\'interconnexion des systèmes de chauffage, ventilation, éclairage, stores et sécurité sur un même bus de données.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'LON','d':'Protocole de communication réseau (Local Operating Network) utilisé dans les systèmes de GTB pour relier les capteurs, actionneurs et automates des installations techniques du bâtiment.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Marché au compteur (M.C.)','d':'Type de contrat d\'exploitation où le prestataire gère les installations et l\'énergie est facturée au réel sur la base des relevés de compteurs, sans garantie de consommation.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Marché climatique (M.T.)','d':'Type de contrat d\'exploitation où la rémunération du prestataire est ajustée en fonction des conditions climatiques réelles (DJU), avec un engagement sur une consommation de référence corrigée du climat.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Marché combustible (C.P.)','d':'Type de contrat d\'exploitation incluant la fourniture de combustible, le prestataire étant responsable de l\'approvisionnement et de la gestion optimale de la consommation.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Marché exploitation sans fourniture (P.F.)','d':'Contrat d\'exploitation dans lequel le prestataire assure la conduite et la maintenance des installations, mais la fourniture d\'énergie reste à la charge du maître d\'ouvrage.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Marché à forfait (M.F.)','d':'Contrat d\'exploitation à prix fixe pour une prestation définie, indépendant des consommations réelles. Le prestataire assume le risque financier lié aux variations de consommation.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Modbus','d':'Protocole de communication série largement utilisé dans l\'industrie et le bâtiment pour interconnecter les automates, capteurs et systèmes de GTB. Il existe en versions RTU (série) et TCP/IP (réseau).','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Onduleur','d':'Dispositif convertissant le courant continu (batteries, panneaux photovoltaïques) en courant alternatif compatible avec le réseau électrique ou les équipements du bâtiment.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Perméabilité à l\'air (Q4Pa-surf, n50)','d':'Indicateur mesurant le débit de fuite d\'air à travers l\'enveloppe du bâtiment sous une pression de référence (4 Pa ou 50 Pa). Plus la valeur est basse, meilleure est l\'étanchéité, ce qui réduit les déperditions thermiques.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Photovoltaïque','d':'Technologie de conversion directe du rayonnement solaire en électricité par des cellules semi-conductrices (silicium). Les panneaux photovoltaïques peuvent être intégrés au bâti (BIPV) ou posés en surimposition.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Pompe à chaleur (PAC)','d':'Machine thermodynamique transférant de la chaleur d\'un milieu froid (air, eau, sol) vers un milieu chaud (chauffage, ECS) en utilisant un cycle de compression/détente d\'un fluide frigorigène. Peut être réversible pour le rafraîchissement.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Pont thermique (PSI)','d':'Zone de l\'enveloppe du bâtiment où la résistance thermique est significativement réduite (jonctions murs/planchers, fenêtres, balcons), provoquant des déperditions de chaleur accrues et des risques de condensation. Mesuré en W/(m.K).','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Protocole BACnet','d':'Standard de communication ISO 16484-5 pour les réseaux d\'automatisation et de contrôle des bâtiments, permettant l\'interopérabilité entre les équipements de différents fabricants (CVC, éclairage, sécurité incendie).','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'PUE (Power Usage Effectiveness)','d':'Indicateur de performance énergétique des datacenters, égal au rapport entre l\'énergie totale consommée par le datacenter et l\'énergie consommée par les seuls équipements informatiques. Un PUE de 1 est optimal ; la moyenne se situe autour de 1,5 à 1,8.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Puits canadien / puits provençal','d':'Système de préchauffage ou de rafraîchissement de l\'air neuf utilisant l\'inertie thermique du sol en faisant circuler l\'air dans des conduits enterrés avant son introduction dans le bâtiment.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'RE2020','d':'Réglementation Environnementale 2020, applicable aux constructions neuves depuis janvier 2022, remplaçant la RT2012. Elle intègre trois axes : sobriété énergétique (Bbio, Cep), réduction de l\'impact carbone (Ic) et confort d\'été (DH).','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'RT2012','d':'Réglementation Thermique 2012, précédant la RE2020, imposant un Bbio maximal, un Cep maximal de 50 kWhEP/m².an modulé et une exigence de confort d\'été. Applicable aux permis de construire déposés entre 2013 et 2021.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Récupération de chaleur','d':'Technique consistant à capter l\'énergie thermique contenue dans les fluides rejetés par le bâtiment (air extrait, eaux usées) pour préchauffer l\'air neuf ou l\'eau froide, améliorant ainsi le rendement global de l\'installation.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Régulation','d':'Ensemble des dispositifs et algorithmes assurant le maintien automatique des paramètres de confort (température, humidité, débit d\'air) à leurs valeurs de consigne, en ajustant en temps réel le fonctionnement des équipements.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Réseau de chaleur','d':'Infrastructure de distribution de chaleur produite centralement (chaufferie, géothermie, récupération de chaleur industrielle) vers un ensemble de bâtiments via un réseau de canalisations d\'eau chaude ou de vapeur.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Réseau de froid','d':'Infrastructure de distribution d\'eau glacée produite centralement pour le rafraîchissement de plusieurs bâtiments, mutualisant la production frigorifique et optimisant les rendements.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'SEER / SCOP','d':'Indicateurs saisonniers de performance des systèmes de climatisation (SEER : Seasonal Energy Efficiency Ratio en mode froid) et des pompes à chaleur (SCOP : Seasonal Coefficient of Performance en mode chaud), tenant compte des variations climatiques annuelles.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Simulation Thermique Dynamique (STD)','d':'Calcul informatique modélisant heure par heure le comportement thermique d\'un bâtiment sur une année type, en intégrant l\'inertie des parois, les apports solaires, l\'occupation et le fonctionnement des systèmes, pour évaluer les consommations et le confort.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Simulation énergétique','d':'Modélisation numérique du comportement énergétique d\'un bâtiment permettant d\'estimer les consommations, d\'évaluer l\'impact de différentes solutions techniques et de vérifier la conformité réglementaire.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Smart building','d':'Bâtiment intelligent intégrant des technologies numériques (capteurs, IoT, GTB, intelligence artificielle) pour optimiser automatiquement le confort des occupants, la performance énergétique et la maintenance.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Smart grid','d':'Réseau électrique intelligent utilisant les technologies numériques pour optimiser la production, la distribution et la consommation d\'électricité en temps réel, favorisant l\'intégration des énergies renouvelables et l\'effacement.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Solaire thermique','d':'Technologie de captation de l\'énergie solaire sous forme de chaleur, via des capteurs (plans vitrés, tubes sous vide), pour la production d\'eau chaude sanitaire, le chauffage des locaux ou le préchauffage de l\'air.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Sous-comptage','d':'Installation de compteurs divisionnaires par usage (chauffage, ECS, refroidissement, éclairage, prises de courant) ou par zone, permettant de suivre et d\'analyser les consommations énergétiques de manière détaillée.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Surventilation nocturne','d':'Technique de rafraîchissement passif consistant à ventiler abondamment le bâtiment la nuit pour évacuer la chaleur accumulée dans les parois et refroidir la masse thermique, améliorant le confort diurne sans climatisation.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Thermographie infrarouge','d':'Technique de diagnostic non destructive utilisant une caméra thermique pour visualiser les déperditions de chaleur, les défauts d\'isolation, les infiltrations d\'air et les ponts thermiques de l\'enveloppe du bâtiment.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Télérelève','d':'Système de collecte automatique à distance des données des compteurs d\'énergie, d\'eau ou de fluides, transmises via un réseau (radio, filaire, Internet) vers une plateforme centralisée de suivi des consommations.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Échangeur thermique','d':'Dispositif permettant le transfert de chaleur entre deux fluides sans mélange (air/air, eau/eau, air/eau), utilisé pour la récupération de chaleur, le chauffage ou le refroidissement.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Énergie finale','d':'Quantité d\'énergie effectivement consommée par l\'utilisateur final (kWh lus sur le compteur), avant application du coefficient de conversion en énergie primaire.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Énergie primaire','d':'Énergie brute non transformée telle qu\'elle est disponible dans la nature (pétrole, gaz, uranium, soleil, vent). L\'énergie finale est multipliée par un coefficient (2,3 pour l\'électricité en France) pour obtenir l\'énergie primaire.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Énergie Renouvelable (EnR)','d':'Énergie issue de sources naturelles inépuisables à l\'échelle humaine : solaire, éolien, hydraulique, biomasse, géothermie. Leur développement est encouragé par la réglementation pour réduire les émissions de GES.','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Étanchéité à l\'air','d':'Performance de l\'enveloppe du bâtiment à limiter les flux d\'air parasites (infiltrations et exfiltrations) à travers les parois, menuiseries et jonctions, mesurée par un test de la porte soufflante (Blower Door).','c':'ÉNERGIE ET PERFORMANCE ÉNERGÉTIQUE'},{'t':'Accès aux vues','d':'Possibilité pour les occupants de disposer d\'une vue directe sur l\'extérieur depuis leur poste de travail ou leur espace de vie, contribuant au bien-être psychologique et à la connexion avec l\'environnement extérieur.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Autonomie en Lumière Naturelle (ALN)','d':'Pourcentage du temps d\'occupation pendant lequel un local atteint un niveau d\'éclairement suffisant (généralement 300 lux) grâce à la seule lumière naturelle, sans recours à l\'éclairage artificiel.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Bruit aérien','d':'Son transmis par l\'air depuis une source (voix, musique, circulation) à travers les parois ou les ouvrants. L\'isolement au bruit aérien est mesuré par l\'indice DnTA ou R\'w.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Bruit d\'impact','d':'Son produit par un choc sur une paroi (pas, chute d\'objets) et transmis par la structure du bâtiment aux locaux adjacents. Mesuré par le niveau de bruit de choc normalisé L\'nT,w.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Bruit d\'équipement','d':'Son émis par les installations techniques du bâtiment (ventilation, ascenseur, pompe, chaudière) perçu dans les locaux occupés. Il est caractérisé par son niveau sonore en dB(A) et sa tonalité.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Bruit de fond','d':'Niveau sonore résiduel permanent dans un local en l\'absence d\'activité humaine, généré par les équipements du bâtiment et l\'environnement extérieur. Un bruit de fond faible est recherché pour le confort acoustique.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Condensation','d':'Passage de l\'eau de l\'état vapeur à l\'état liquide au contact d\'une surface froide dont la température est inférieure au point de rosée de l\'air ambiant. Elle provoque des dégradations et favorise le développement de moisissures.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Confort acoustique','d':'État de bien-être d\'un occupant par rapport à l\'ambiance sonore de son environnement, résultant d\'un isolement suffisant aux bruits extérieurs et intérieurs, d\'une maîtrise de la réverbération et d\'un bruit de fond faible.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Confort hygrothermique','d':'Sensation de bien-être thermique d\'un occupant, résultant de la combinaison de la température de l\'air, de la température des parois, de l\'humidité relative, de la vitesse de l\'air et du niveau d\'activité et d\'habillement.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Confort olfactif','d':'Absence de gêne liée aux odeurs dans un local, dépendant de la qualité de l\'air intérieur, du taux de renouvellement d\'air et de la maîtrise des sources d\'émissions olfactives (matériaux, activités, extérieur).','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Confort thermique','d':'État de satisfaction d\'un individu vis-à-vis de son environnement thermique, évalué selon la norme ISO 7730 par les indices PMV (Vote Moyen Prévisible) et PPD (Pourcentage Prévisible d\'Insatisfaits).','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Confort visuel','d':'Conditions d\'éclairage naturel et artificiel procurant un environnement lumineux agréable, sans éblouissement, avec un niveau d\'éclairement suffisant et uniforme, et un accès aux vues extérieures.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Décibel (dB / dB(A))','d':'Unité logarithmique de mesure de l\'intensité sonore. Le dB(A) est pondéré pour refléter la sensibilité de l\'oreille humaine aux différentes fréquences. Un écart de 3 dB correspond à un doublement de la puissance sonore.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Facteur de Lumière du Jour (FLJ)','d':'Rapport, exprimé en pourcentage, entre l\'éclairement naturel intérieur en un point d\'un local et l\'éclairement extérieur horizontal simultané sous un ciel couvert standardisé (CIE). Plus le FLJ est élevé, meilleur est l\'apport de lumière naturelle.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Humidité relative (HR)','d':'Rapport entre la quantité de vapeur d\'eau contenue dans l\'air et la quantité maximale que cet air pourrait contenir à la même température, exprimé en pourcentage. Une HR entre 40 et 60 % est généralement considérée comme confortable.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Hygrométrie','d':'Mesure du taux d\'humidité de l\'air. En confort du bâtiment, elle conditionne la sensation thermique, le risque de condensation et le développement de moisissures. Un contrôle hygrométrique est essentiel pour la santé et le confort.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Isolement acoustique (DnTA)','d':'Isolement acoustique standardisé pondéré entre deux locaux ou entre l\'extérieur et un local, exprimé en décibels. Il intègre le spectre du bruit (terme d\'adaptation C ou Ctr) et la correction liée au volume du local récepteur.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Luminance','d':'Intensité lumineuse émise ou réfléchie par une surface dans une direction donnée, rapportée à l\'aire apparente de cette surface, exprimée en candelas par mètre carré (cd/m²). Une luminance excessive provoque l\'éblouissement.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Niveau d\'éclairement (lux)','d':'Flux lumineux reçu par unité de surface, exprimé en lux (1 lux = 1 lumen/m²). Les niveaux recommandés varient selon l\'activité : 300 lux pour un bureau, 500 lux pour un travail de précision, 100 lux pour une circulation.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Niveau de bruit','d':'Intensité sonore mesurée ou calculée dans un local, exprimée en dB(A). Les seuils réglementaires varient selon le type de local et l\'usage (35 dB(A) en chambre, 40-45 dB(A) en bureau, etc.).','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Point de rosée','d':'Température à laquelle l\'air, à pression constante, devient saturé en vapeur d\'eau et provoque la condensation. Paramètre essentiel pour le dimensionnement de l\'isolation et la prévention des pathologies liées à l\'humidité.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Temps de réverbération (Tr)','d':'Durée, en secondes, nécessaire pour que le niveau sonore dans un local décroisse de 60 dB après l\'arrêt de la source sonore. Calculé comme la moyenne des temps de réverbération aux fréquences 500, 1000 et 2000 Hz. Un Tr court améliore l\'intelligibilité de la parole.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Température opérative','d':'Moyenne pondérée de la température de l\'air et de la température moyenne de rayonnement des parois environnantes, représentant la température réellement ressentie par un occupant.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Transmission lumineuse (TLw)','d':'Proportion de la lumière naturelle traversant un vitrage, exprimée en pourcentage. Un TLw élevé favorise l\'éclairage naturel des locaux, tandis qu\'un TLw faible est choisi pour limiter les apports solaires ou l\'éblouissement.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'UGR (Unified Glare Rating)','d':'Indice normalisé (EN 12464-1) quantifiant le degré d\'éblouissement d\'inconfort produit par un système d\'éclairage artificiel dans un espace intérieur. Plus l\'UGR est bas, moins il y a d\'éblouissement (recommandé : ≤19 en bureau).','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Uniformité d\'éclairement','d':'Rapport entre l\'éclairement minimal et l\'éclairement moyen sur un plan de travail. Une uniformité élevée (≥0,6 pour la zone de travail) garantit un éclairage homogène et réduit la fatigue visuelle.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Vue sur l\'extérieur','d':'Ouverture visuelle depuis un espace intérieur vers le paysage extérieur, évaluée par la taille et la position des fenêtres, la distance aux obstacles et l\'angle de vue. Elle contribue au bien-être et à la régulation du rythme circadien.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Éblouissement','d':'Gêne visuelle provoquée par une luminance excessive dans le champ de vision (soleil direct, reflet, luminaire non protégé), pouvant réduire la performance visuelle et le confort. Maîtrisé par des protections solaires, des stores ou un éclairage adapté.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Émergence','d':'Différence entre le niveau de bruit mesuré en présence de la source sonore considérée (équipement technique) et le niveau de bruit de fond résiduel. L\'émergence est limitée réglementairement pour éviter les nuisances.','c':'CONFORT (THERMIQUE, ACOUSTIQUE, VISUEL, OLFACTIF)'},{'t':'Acétaldéhyde','d':'Composé organique volatil (COV) potentiellement irritant pour les voies respiratoires, émis par certains matériaux de construction, peintures et vernis. Polluant surveillé dans le cadre de la QAI avec un seuil guide.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Amiante','d':'Fibre minérale naturelle utilisée historiquement dans la construction pour ses propriétés isolantes et ignifuges, désormais interdite en France depuis 1997 en raison de sa cancérogénicité (mésothéliome, cancer du poumon). Sa présence dans les bâtiments anciens nécessite un diagnostic (DTA) et une gestion rigoureuse.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Balise CO2','d':'Capteur mesurant en continu la concentration de dioxyde de carbone dans l\'air intérieur, utilisé comme indicateur du taux de renouvellement d\'air et du confinement d\'un local. Souvent couplé à la régulation de la ventilation.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Benzène','d':'Composé organique volatil classé cancérogène certain (groupe 1 CIRC), pouvant être présent dans l\'air intérieur par émission des matériaux, du mobilier ou par infiltration depuis l\'extérieur (trafic routier). Valeur guide QAI : 2 µg/m³.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Bloc Homogène (BH)','d':'Zone du bâtiment définie par des conditions homogènes de ventilation, d\'occupation et d\'exposition aux polluants, utilisée comme unité de base pour les mesures et la surveillance de la qualité de l\'air intérieur.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Bouche d\'extraction / d\'insufflation','d':'Terminal aéraulique permettant respectivement l\'évacuation de l\'air vicié (extraction) ou l\'introduction d\'air neuf (insufflation) dans un local, dimensionné pour assurer les débits réglementaires de ventilation.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Bq/m³ (Becquerels par mètre cube)','d':'Unité de mesure de l\'activité volumique du radon dans l\'air intérieur. Le seuil réglementaire français est de 300 Bq/m³ pour les ERP et les habitations, au-delà duquel des actions correctives sont nécessaires.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Cancérigène / CMR (Cancérogène, Mutagène, Reprotoxique)','d':'Substance chimique capable de provoquer un cancer (cancérogène), des mutations génétiques (mutagène) ou des effets néfastes sur la reproduction (reprotoxique). Leur utilisation dans les produits de construction est strictement encadrée par REACH.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Champignon','d':'Micro-organisme se développant dans les environnements humides et mal ventilés, pouvant provoquer des dégradations des matériaux (mérule, champignons lignivores) et des problèmes de santé (allergies, infections respiratoires).','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'CIRC (Centre International de Recherche sur le Cancer)','d':'Agence de l\'OMS classifiant les agents chimiques, physiques et biologiques selon leur potentiel cancérogène pour l\'homme : groupe 1 (cancérogène certain), 2A (probable), 2B (possible), 3 (inclassable).','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Classe de filtration (ISO 16890)','d':'Classification des filtres à air selon leur efficacité de capture des particules fines, mesurée sur les fractions ePM1, ePM2,5 et ePM10. Remplace l\'ancienne classification G/M/F (EN 779).','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'CO (Monoxyde de carbone)','d':'Gaz inodore et incolore produit par la combustion incomplète des combustibles (gaz, bois, fioul). Extrêmement toxique, il se fixe sur l\'hémoglobine et peut provoquer intoxications graves voire décès. Sa détection est obligatoire dans certains locaux.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'CO2 (Dioxyde de carbone)','d':'Gaz naturellement présent dans l\'air (environ 400 ppm), produit par la respiration humaine et la combustion. Utilisé comme indicateur du confinement d\'un local : au-delà de 1 000 ppm, le renouvellement d\'air est jugé insuffisant.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'COV (Composés Organiques Volatils)','d':'Famille de substances chimiques contenant du carbone, qui s\'évaporent à température ambiante. Émis par les matériaux de construction, les peintures, les colles, les meubles et les produits d\'entretien. Certains sont irritants ou cancérogènes.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'COVT (Composés Organiques Volatils Totaux)','d':'Concentration totale de l\'ensemble des COV mesurés dans l\'air intérieur, exprimée en µg/m³. Indicateur global de la charge polluante organique de l\'air, dont la valeur guide est de 300 µg/m³ selon le décret QAI.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'CTA (Centrale de Traitement d\'Air)','d':'Équipement aéraulique assurant le traitement (filtration, chauffage, refroidissement, humidification, déshumidification) et la distribution de l\'air neuf ou recyclé dans les locaux, via un réseau de gaines.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Débit d\'air neuf','d':'Volume d\'air extérieur introduit par unité de temps dans un local pour renouveler l\'air intérieur, exprimé en m³/h ou en l/s par personne. Fixé par la réglementation selon le type de local et l\'occupation.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Désenfumage','d':'Ensemble des dispositifs (ouvrants, gaines, ventilateurs) permettant l\'évacuation des fumées et des gaz chauds en cas d\'incendie, afin de faciliter l\'évacuation des occupants et l\'intervention des secours.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Filtration de l\'air','d':'Procédé d\'épuration de l\'air consistant à retenir les particules en suspension (poussières, pollens, particules fines) sur un média filtrant, avant l\'introduction de l\'air dans les locaux. La qualité de filtration est classée selon l\'ISO 16890.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Filtre HEPA','d':'Filtre à très haute efficacité (High Efficiency Particulate Air) retenant au moins 99,97 % des particules de 0,3 µm. Utilisé dans les environnements nécessitant une propreté de l\'air exceptionnelle (salles blanches, hôpitaux).','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Formaldéhyde','d':'Composé organique volatil classé cancérogène certain (groupe 1 CIRC), émis par les panneaux de bois aggloméré, les colles, les mousses isolantes et certains produits d\'entretien. Valeur guide réglementaire QAI : 30 µg/m³ (objectif cible) à 100 µg/m³ (seuil d\'action).','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Module d\'entrée d\'air','d':'Dispositif installé dans les menuiseries ou les murs permettant l\'admission d\'air neuf dans les locaux en ventilation naturelle ou en VMC simple flux par extraction. Son débit est calibré pour assurer le renouvellement d\'air réglementaire.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Moisissure','d':'Champignon microscopique se développant sur les surfaces humides (murs, plafonds, joints), produisant des spores allergènes et des mycotoxines. Indicateur d\'un problème d\'humidité et/ou de ventilation insuffisante dans le bâtiment.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Naphtalène','d':'Hydrocarbure aromatique polycyclique (HAP) pouvant être présent dans l\'air intérieur, émis par certains matériaux et produits. Classé cancérogène possible (groupe 2B CIRC). Polluant surveillé dans les campagnes de mesure QAI.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'NO2 (Dioxyde d\'azote)','d':'Gaz irritant pour les voies respiratoires, produit par les moteurs à combustion et les appareils de chauffage au gaz. Sa présence en air intérieur provient principalement de l\'extérieur (trafic routier) ou de sources de combustion internes.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'O3 (Ozone)','d':'Gaz oxydant puissant, présent dans l\'air intérieur à faible concentration, provenant de l\'air extérieur ou émis par certains équipements (photocopieurs, imprimantes laser). Irritant pour les voies respiratoires à forte concentration.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Particules fines (PM2.5 / PM10)','d':'Particules en suspension dans l\'air de diamètre inférieur à 2,5 µm (PM2.5) ou 10 µm (PM10). Les PM2.5, les plus dangereuses, pénètrent profondément dans les poumons et peuvent atteindre le sang. Elles proviennent de la combustion, du trafic et des activités intérieures.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Plomb','d':'Métal lourd toxique pour le système nerveux, autrefois utilisé dans les peintures (céruse) et les canalisations d\'eau. Sa présence dans les bâtiments anciens est diagnostiquée par le CREP. Seuil d\'intervention : 1 mg/cm² en peinture.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'PPM (parties par million)','d':'Unité de mesure de la concentration d\'un gaz dans l\'air (1 ppm = 1 cm³ de gaz par m³ d\'air). Couramment utilisée pour exprimer les concentrations de CO₂ (seuil de 1 000 ppm en confinement) et de CO.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Qualité de l\'Air Intérieur (QAI)','d':'Caractérisation de l\'air présent dans les espaces clos en termes de concentrations de polluants (COV, particules, CO₂, radon, etc.) et de renouvellement d\'air. Une bonne QAI est essentielle à la santé et au confort des occupants. En HQE, elle est évaluée par simulation, cahier des charges ou mesures in situ.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Radon','d':'Gaz radioactif naturel, inodore et incolore, issu de la désintégration de l\'uranium et du radium présents dans le sol. Il s\'infiltre dans les bâtiments par les fondations. Classé cancérogène pulmonaire (groupe 1 CIRC), avec un seuil réglementaire de 300 Bq/m³.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Sonde de qualité d\'air','d':'Capteur mesurant en continu un ou plusieurs paramètres de la qualité de l\'air intérieur (CO₂, COV, PM2.5, température, humidité), pouvant être connecté à la GTB pour piloter la ventilation en fonction des besoins réels.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Taux de renouvellement d\'air','d':'Nombre de fois par heure où le volume d\'air d\'un local est entièrement renouvelé par de l\'air neuf. Il est défini réglementairement selon le type de local et l\'occupation pour garantir une QAI satisfaisante.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Toluène','d':'Solvant organique (COV) émis par les peintures, les vernis, les colles et certains matériaux de construction. Irritant pour les voies respiratoires et le système nerveux. Polluant surveillé dans les campagnes de mesure QAI.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Ventilation mécanique','d':'Système de renouvellement de l\'air utilisant des ventilateurs pour assurer l\'introduction d\'air neuf et/ou l\'extraction d\'air vicié de manière contrôlée, indépendamment des conditions climatiques extérieures.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Ventilation naturelle','d':'Renouvellement de l\'air intérieur par l\'effet du vent et du tirage thermique (différence de température entre intérieur et extérieur), sans recours à des ventilateurs mécaniques, via des ouvertures (fenêtres, grilles, conduits).','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'VMC (Ventilation Mécanique Contrôlée)','d':'Système de ventilation mécanique assurant le renouvellement permanent de l\'air intérieur. En simple flux, seule l\'extraction est mécanique ; en double flux, l\'insufflation et l\'extraction sont mécaniques avec récupération de chaleur.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'VMC double flux','d':'Système de ventilation mécanique où l\'air neuf insufflé et l\'air vicié extrait circulent dans des réseaux séparés, reliés par un échangeur thermique récupérant jusqu\'à 90 % de la chaleur de l\'air extrait pour préchauffer l\'air neuf entrant.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Xylènes','d':'Solvants organiques (COV) présents dans les peintures, vernis et adhésifs. Irritants pour les muqueuses et les voies respiratoires. Polluants mesurés dans le cadre de la surveillance de la QAI.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'µg/m³ (microgrammes par mètre cube)','d':'Unité de mesure de la concentration massique d\'un polluant dans l\'air, correspondant à un millionième de gramme par mètre cube d\'air. Utilisée pour exprimer les seuils réglementaires de la QAI (formaldéhyde, benzène, PM2.5, etc.).','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Étiquetage sanitaire des produits (A+, A, B, C)','d':'Classification obligatoire des produits de construction et de décoration selon leurs émissions de COV dans l\'air intérieur. La classe A+ correspond aux plus faibles émissions. Imposé par le décret n° 2011-321 et l\'arrêté du 19 avril 2011.','c':'QUALITÉ DE L\'AIR INTÉRIEUR (QAI)'},{'t':'Adoucisseur','d':'Appareil de traitement de l\'eau réduisant sa dureté (teneur en calcium et magnésium) par échange d\'ions, afin de limiter le tartre dans les canalisations et les équipements. Son entretien régulier est essentiel pour maintenir la qualité sanitaire de l\'eau.','c':'QUALITÉ DE L\'EAU'},{'t':'Analyse de l\'eau','d':'Ensemble de tests physico-chimiques et microbiologiques réalisés sur des prélèvements d\'eau du réseau intérieur pour vérifier sa conformité aux normes de potabilité et détecter d\'éventuelles contaminations (légionelles, plomb, etc.).','c':'QUALITÉ DE L\'EAU'},{'t':'Anti-bélier','d':'Dispositif hydraulique absorbant les surpressions brutales (coups de bélier) dans les canalisations, causées par la fermeture rapide d\'une vanne ou l\'arrêt d\'une pompe, protégeant ainsi le réseau contre les dommages mécaniques.','c':'QUALITÉ DE L\'EAU'},{'t':'Bras mort','d':'Tronçon de canalisation en cul-de-sac où l\'eau stagne, créant des conditions favorables au développement bactérien, notamment des légionelles. Leur élimination ou leur purge régulière est une exigence sanitaire majeure.','c':'QUALITÉ DE L\'EAU'},{'t':'Carnet sanitaire','d':'Document de suivi obligatoire pour les ERP, enregistrant toutes les opérations de maintenance, les analyses d\'eau, les températures relevées et les interventions réalisées sur le réseau d\'eau du bâtiment, dans le cadre de la prévention du risque légionelles.','c':'QUALITÉ DE L\'EAU'},{'t':'Chasse d\'eau','d':'Dispositif de rinçage des appareils sanitaires. Les modèles à double commande (3/6 litres ou 2/4 litres) permettent de réduire la consommation d\'eau. En HQE, le choix d\'équipements hydro-économes est évalué.','c':'QUALITÉ DE L\'EAU'},{'t':'Chloration / chlore résiduel','d':'Traitement de désinfection de l\'eau par ajout de chlore, laissant un résiduel de chlore libre dans le réseau pour maintenir la qualité bactériologique. Un taux de chlore résiduel insuffisant favorise le développement de légionelles.','c':'QUALITÉ DE L\'EAU'},{'t':'Clapet anti-retour','d':'Dispositif mécanique empêchant le retour d\'eau dans le sens opposé à l\'écoulement normal, protégeant le réseau d\'eau potable contre les risques de contamination par retour d\'eau polluée.','c':'QUALITÉ DE L\'EAU'},{'t':'Disconnecteur','d':'Dispositif de protection du réseau d\'eau potable contre les retours d\'eau par une zone de mise à l\'atmosphère, offrant une protection supérieure au clapet anti-retour. Obligatoire sur certaines installations (chauffage, arrosage, process industriel).','c':'QUALITÉ DE L\'EAU'},{'t':'Eau Chaude Sanitaire (ECS)','d':'Eau destinée aux usages domestiques (toilette, vaisselle, nettoyage), chauffée entre 50 et 60°C au point de production et distribuée à une température supérieure à 50°C en réseau bouclé pour prévenir le risque légionelles.','c':'QUALITÉ DE L\'EAU'},{'t':'Eaux grises','d':'Eaux usées peu chargées en polluants, provenant des lavabos, douches et machines à laver. Elles peuvent être récupérées, traitées et réutilisées pour des usages non potables (chasses d\'eau, arrosage).','c':'QUALITÉ DE L\'EAU'},{'t':'Eaux usées','d':'Eaux rejetées après utilisation domestique ou industrielle, contenant des polluants organiques, chimiques ou microbiologiques, nécessitant un traitement en station d\'épuration avant rejet dans le milieu naturel.','c':'QUALITÉ DE L\'EAU'},{'t':'Filtre anti-tartre','d':'Dispositif de traitement de l\'eau réduisant la formation de dépôts calcaires dans les canalisations et les équipements, par filtration, traitement magnétique ou électronique, sans modifier la composition chimique de l\'eau.','c':'QUALITÉ DE L\'EAU'},{'t':'Légionelles (Legionella)','d':'Bactéries naturellement présentes dans l\'eau douce, pouvant proliférer dans les réseaux d\'eau tiède (25-45°C) et les installations de refroidissement. Transmises par inhalation d\'aérosols, elles provoquent la légionellose, infection pulmonaire grave.','c':'QUALITÉ DE L\'EAU'},{'t':'Mitigeur thermostatique','d':'Robinet régulant automatiquement la température de l\'eau distribuée en mélangeant eau chaude et eau froide, assurant une température stable et limitant le risque de brûlure tout en maintenant une température suffisante dans le réseau.','c':'QUALITÉ DE L\'EAU'},{'t':'Norme NF T 90-431','d':'Norme française définissant la méthode de référence pour la recherche et le dénombrement des Legionella dans l\'eau par culture sur gélose, utilisée pour les analyses réglementaires dans les ERP.','c':'QUALITÉ DE L\'EAU'},{'t':'Paramètres microbiologiques','d':'Indicateurs de la qualité bactériologique de l\'eau : concentration en Legionella, Escherichia coli, entérocoques, Pseudomonas aeruginosa, etc. Leur surveillance est obligatoire dans les réseaux intérieurs des ERP.','c':'QUALITÉ DE L\'EAU'},{'t':'Paramètres physico-chimiques','d':'Caractéristiques mesurables de l\'eau (pH, dureté, turbidité, température, teneur en chlore, en plomb, en cuivre) permettant d\'évaluer sa conformité aux normes de potabilité et l\'état du réseau intérieur.','c':'QUALITÉ DE L\'EAU'},{'t':'Point d\'usage','d':'Terminal de distribution d\'eau (robinet, douche, fontaine) où l\'eau est prélevée par l\'usager. Le contrôle de la qualité de l\'eau au point d\'usage est essentiel car la contamination peut se produire dans les derniers mètres du réseau.','c':'QUALITÉ DE L\'EAU'},{'t':'Potabilité','d':'Aptitude d\'une eau à être consommée sans risque pour la santé, définie par des limites de qualité microbiologiques, chimiques et organoleptiques fixées par le Code de la Santé Publique et les directives européennes.','c':'QUALITÉ DE L\'EAU'},{'t':'Retour de boucle','d':'Point où l\'eau chaude sanitaire revient au système de production après avoir circulé dans l\'ensemble du réseau bouclé. La température au retour de boucle doit être supérieure à 50°C pour prévenir la prolifération des légionelles.','c':'QUALITÉ DE L\'EAU'},{'t':'Risque légionelles','d':'Probabilité de contamination des occupants par des bactéries Legionella via les réseaux d\'eau chaude ou les systèmes de refroidissement du bâtiment. Prévenu par le maintien de températures adéquates, l\'élimination des bras morts et la surveillance régulière.','c':'QUALITÉ DE L\'EAU'},{'t':'Robinetterie','d':'Ensemble des appareils de distribution et de régulation de l\'eau dans un bâtiment (robinets, vannes, mitigeurs). En HQE, la robinetterie hydro-économe (temporisée, à détection, à débit limité) contribue à la réduction de la consommation d\'eau.','c':'QUALITÉ DE L\'EAU'},{'t':'Récupération des eaux de pluie','d':'Collecte et stockage de l\'eau de pluie (toitures) dans des cuves pour une réutilisation à des fins non potables (arrosage, nettoyage, chasses d\'eau), réduisant la consommation d\'eau potable et les rejets d\'eaux pluviales.','c':'QUALITÉ DE L\'EAU'},{'t':'Réseau bouclé','d':'Configuration du réseau d\'eau chaude sanitaire dans laquelle l\'eau circule en permanence dans une boucle fermée entre la production et les points d\'usage, maintenant une température suffisante pour prévenir le développement des légionelles.','c':'QUALITÉ DE L\'EAU'},{'t':'Seuil d\'action','d':'Concentration en Legionella dans l\'eau (1 000 UFC/L) au-delà de laquelle des actions correctives doivent être engagées (nettoyage, désinfection, purge) selon la réglementation française de prévention des légionelles.','c':'QUALITÉ DE L\'EAU'},{'t':'Seuil d\'alerte','d':'Concentration critique en Legionella dans l\'eau (10 000 UFC/L) déclenchant des mesures d\'urgence : restriction d\'usage, choc thermique ou chimique, signalement aux autorités sanitaires (ARS) et investigation des causes.','c':'QUALITÉ DE L\'EAU'},{'t':'Température de consigne ECS','d':'Température cible de l\'eau chaude sanitaire fixée dans le système de production et de distribution. La réglementation impose un stockage à 60°C minimum et une distribution à 50°C minimum en tout point du réseau bouclé pour lutter contre les légionelles.','c':'QUALITÉ DE L\'EAU'},{'t':'Antenne relais','d':'Installation de télécommunication mobile émettant et recevant des ondes radiofréquences pour la couverture du réseau téléphonique. Sa proximité avec un bâtiment est un facteur d\'exposition aux champs électromagnétiques haute fréquence.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Basse fréquence (BF)','d':'Gamme de fréquences du spectre électromagnétique comprise entre 30 Hz et 300 kHz, correspondant aux champs émis par les lignes électriques, les transformateurs et les appareils électriques domestiques. Mesurée en µT (micro Tesla).','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Blindage','d':'Technique de protection consistant à entourer une source d\'émission ou un local sensible d\'un matériau conducteur (tôle, treillis métallique, peinture à base de carbone) pour atténuer la propagation des champs électromagnétiques.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Cage de Faraday','d':'Enceinte métallique fermée bloquant la pénétration ou la sortie des champs électromagnétiques. Principe utilisé pour le blindage de certains locaux sensibles (salles serveurs, laboratoires, chambres médicales).','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Champ électromagnétique','d':'Combinaison d\'un champ électrique (V/m) et d\'un champ magnétique (µT) se propageant sous forme d\'ondes à la vitesse de la lumière. L\'exposition des occupants aux champs EM est encadrée par les seuils réglementaires (décret n° 2002-775).','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'CPL (Courants Porteurs en Ligne)','d':'Technologie de communication utilisant le réseau électrique existant pour transmettre des données numériques. Elle peut générer des émissions électromagnétiques parasites dans la gamme des hautes fréquences (1-30 MHz), à évaluer en HQE.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'DAS (Débit d\'Absorption Spécifique)','d':'Quantité d\'énergie électromagnétique absorbée par unité de masse de tissu biologique, exprimée en W/kg. Utilisé pour caractériser l\'exposition locale du corps humain aux ondes radiofréquences (téléphones mobiles, Wi-Fi).','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Hyperfréquence','d':'Gamme de fréquences du spectre électromagnétique comprise entre 300 MHz et 300 GHz, correspondant aux émissions des antennes relais, du Wi-Fi, du Bluetooth, des fours à micro-ondes et des radars.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Onde électromagnétique','d':'Perturbation du champ électromagnétique se propageant dans l\'espace. En HQE, les ondes sont classées par fréquence (basse, haute) et leur impact sur les occupants est évalué par des mesures in situ en V/m et µT.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Principe ALARA','d':'Acronyme de « As Low As Reasonably Achievable » (aussi bas que raisonnablement possible). Principe de radioprotection recommandant de maintenir l\'exposition aux rayonnements et aux champs EM au niveau le plus bas possible, au-delà du simple respect des seuils réglementaires.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Principe de précaution','d':'Principe de droit environnemental selon lequel l\'absence de certitudes scientifiques absolues ne doit pas retarder l\'adoption de mesures visant à prévenir un risque de dommages graves et irréversibles. Appliqué en HQE pour l\'exposition aux ondes.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Très basse fréquence (TBF / EBF)','d':'Gamme de fréquences électromagnétiques inférieures à 30 Hz, incluant les champs générés par le réseau électrique 50 Hz. L\'exposition chronique à ces champs est un sujet de vigilance sanitaire.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'V/m (Volt par mètre)','d':'Unité de mesure de l\'intensité du champ électrique, utilisée pour quantifier l\'exposition aux ondes électromagnétiques haute fréquence. Les seuils réglementaires français varient de 28 à 61 V/m selon la fréquence.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Wi-Fi','d':'Technologie de réseau sans fil utilisant des ondes radiofréquences (2,4 GHz et 5 GHz) pour la transmission de données. En HQE, l\'exposition des occupants au Wi-Fi est évaluée et des alternatives filaires peuvent être recommandées dans les zones sensibles.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'µT (microTesla)','d':'Unité de mesure de l\'induction magnétique basse fréquence, utilisée pour caractériser l\'exposition aux champs magnétiques générés par les lignes électriques et les équipements électriques. Seuil réglementaire : 100 µT à 50 Hz.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Électrosensibilité','d':'Syndrome regroupant des symptômes non spécifiques (maux de tête, fatigue, troubles du sommeil) attribués par les personnes concernées à l\'exposition aux champs électromagnétiques. Non reconnu comme pathologie mais pris en compte dans le principe de précaution.','c':'ONDES ÉLECTROMAGNÉTIQUES'},{'t':'Agent de commissioning','d':'Professionnel qualifié chargé de conduire la démarche de commissionnement : définition du périmètre, planification des essais, vérification des performances des systèmes et rédaction du rapport. Il peut être interne ou externe à l\'équipe de maîtrise d\'œuvre.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Autocontrôle','d':'Vérification réalisée par l\'entreprise ayant exécuté les travaux pour s\'assurer que l\'installation est conforme aux prescriptions du marché et fonctionne correctement, avant la réception par le maître d\'ouvrage.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'BIM (Building Information Modeling)','d':'Processus de modélisation numérique 3D du bâtiment intégrant l\'ensemble des informations techniques (géométrie, matériaux, équipements, performances) sur tout le cycle de vie, facilitant la conception, la construction et l\'exploitation.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Carnet numérique du bâtiment','d':'Document dématérialisé regroupant l\'ensemble des informations utiles à la gestion, à la maintenance et à l\'exploitation du bâtiment : plans, fiches techniques, historique des interventions, consommations, diagnostics.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'CBCF (Certification)','d':'Certification Building Commissioning Firm, attestant la compétence d\'un organisme à réaliser des missions de commissionnement de bâtiments selon des référentiels reconnus.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'CBCP (Commissioning Building Certification Professional)','d':'Certification individuelle attestant la compétence d\'un professionnel dans le domaine du commissionnement des bâtiments, délivrée par des organismes de certification reconnus.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Commissioning','d':'Processus systématique et documenté de vérification que les systèmes techniques d\'un bâtiment sont conçus, installés, mis en service et exploités conformément aux objectifs de performance définis par le maître d\'ouvrage. Il comprend la définition des objectifs, la planification, les essais, le suivi et le reporting.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Contrat de moyens','d':'Contrat d\'exploitation dans lequel le prestataire s\'engage à mettre en œuvre les moyens humains et techniques nécessaires à la maintenance, sans garantie de résultat sur les performances énergétiques ou de confort.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Contrat de résultat','d':'Contrat d\'exploitation dans lequel le prestataire s\'engage sur l\'atteinte d\'objectifs de performance mesurables (consommation, température, disponibilité), avec un mécanisme d\'intéressement et de pénalités.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Contrôle tiers','d':'Vérification réalisée par un organisme indépendant (ni maître d\'ouvrage, ni installateur) pour attester la conformité des installations et le bon fonctionnement des systèmes, apportant une garantie d\'objectivité.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Criticité de l\'intervention','d':'Classification du degré d\'urgence et d\'importance d\'une intervention de maintenance, tenant compte de l\'impact sur la sécurité, le confort des occupants, la continuité de service et les coûts. Utilisée pour prioriser les ordres de travail.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'DIUO (Dossier d\'Interventions Ultérieures sur l\'Ouvrage)','d':'Document réglementaire (Code du Travail) établi pendant la conception et la construction, recensant les dispositions prises pour faciliter les interventions de maintenance et d\'entretien ultérieures en sécurité.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'DOE (Dossier des Ouvrages Exécutés)','d':'Ensemble des documents techniques remis au maître d\'ouvrage à la réception des travaux, comprenant les plans conformes à l\'exécution, les notices techniques, les PV d\'essais, les manuels d\'utilisation et d\'entretien des équipements.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Délai de remise en l\'état','d':'Durée maximale contractuelle accordée au prestataire de maintenance pour rétablir un équipement ou un local dans son état de fonctionnement normal après une panne ou un incident.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Délai de remise en service','d':'Durée maximale contractuelle entre le signalement d\'une panne et la remise en service de l\'équipement concerné, incluant le diagnostic, l\'intervention et la vérification du fonctionnement.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Exploitant','d':'Personne physique ou morale chargée du fonctionnement quotidien des installations techniques du bâtiment : conduite des équipements, surveillance, réglages, petites interventions de maintenance courante.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Gamme de maintenance','d':'Document technique décrivant de manière détaillée les opérations de maintenance préventive à réaliser sur un équipement : nature de l\'intervention, fréquence, durée estimée, compétences requises, pièces de rechange et outillage nécessaire.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Garantie de performance','d':'Engagement contractuel du prestataire d\'exploitation à atteindre des niveaux de performance mesurables (énergétique, QAI, confort), avec des indicateurs, des méthodes de vérification et des mécanismes de pénalités/bonus.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Gestionnaire','d':'Personne physique ou morale responsable de la gestion administrative, financière et technique d\'un bâtiment ou d\'un patrimoine immobilier, assurant la coordination entre les différents prestataires et le suivi des performances.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'GMAO (Gestion de la Maintenance Assistée par Ordinateur)','d':'Logiciel de gestion centralisant la planification, le suivi et l\'historique de toutes les opérations de maintenance (préventive et corrective) sur les équipements du bâtiment, incluant la gestion des stocks de pièces et la traçabilité des interventions.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Indicateur de résultat','d':'Grandeur mesurable permettant d\'évaluer objectivement l\'atteinte d\'un objectif de performance en exploitation : consommation énergétique (kWh/m².an), taux de disponibilité des équipements, nombre de plaintes, température moyenne, etc.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Jumeau numérique','d':'Réplique virtuelle dynamique d\'un bâtiment physique, alimentée en temps réel par les données des capteurs et de la GTB, permettant de simuler, optimiser et anticiper le comportement du bâtiment et de ses systèmes.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Maintenance corrective','d':'Intervention de maintenance réalisée après la détection d\'une défaillance, visant à remettre l\'équipement en état de fonctionnement. Elle peut être palliative (dépannage provisoire) ou curative (réparation définitive).','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Maintenance curative','d':'Réparation définitive d\'un équipement défaillant, visant à éliminer la cause de la panne et à rétablir durablement ses performances nominales, par opposition au dépannage provisoire (maintenance palliative).','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Maintenance préventive','d':'Interventions planifiées et programmées selon un calendrier ou des indicateurs d\'usure, réalisées avant la survenue d\'une panne pour maintenir les équipements en état de fonctionnement optimal et prolonger leur durée de vie.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Maquette numérique','d':'Représentation numérique 3D du bâtiment regroupant l\'ensemble des données géométriques et techniques, servant de base au BIM. Elle est utilisée en conception, construction et exploitation pour centraliser l\'information du projet.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Niveaux de maintenance (I à IV, AFNOR FDX 60-000)','d':'Classification AFNOR des interventions de maintenance selon leur complexité : Niveau I (réglages simples par l\'exploitant), Niveau II (opérations mineures par technicien), Niveau III (diagnostic et réparation par spécialiste), Niveau IV (travaux importants par entreprise spécialisée).','c':'MAINTENANCE ET EXPLOITATION'},{'t':'OPQIBI','d':'Organisme de Qualification de l\'Ingénierie (anciennement Organisme Professionnel de Qualification de l\'Ingénierie du Bâtiment et de l\'Industrie), délivrant des qualifications attestant la compétence des bureaux d\'études et d\'ingénierie.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Ordre de Travail (OT)','d':'Document émis par la GMAO ou le gestionnaire prescrivant une intervention de maintenance sur un équipement, précisant sa nature, sa priorité, le délai d\'exécution et les ressources nécessaires.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Plan de maintenance','d':'Document structurant l\'organisation de la maintenance d\'un bâtiment : inventaire des équipements, gammes de maintenance associées, fréquences d\'intervention, planification annuelle, budget prévisionnel et indicateurs de suivi.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Processus de maintenance','d':'Enchaînement organisé des étapes allant de la détection d\'un besoin de maintenance à la clôture de l\'intervention : signalement, diagnostic, planification, exécution, vérification, capitalisation dans la GMAO.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Rapport Mensuel d\'Activité (RMA)','d':'Document établi mensuellement par le prestataire de maintenance, synthétisant les interventions réalisées, les indicateurs de performance, les consommations, les incidents et les actions correctives en cours.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Recommissionnement','d':'Reprise du processus de commissionnement sur un bâtiment existant dont les performances se sont dégradées, afin de rétablir le fonctionnement optimal des systèmes par des réglages, des corrections et des mises à jour.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Reporting','d':'Activité de collecte, de traitement et de présentation synthétique des données d\'exploitation (consommations, incidents, interventions, indicateurs) sous forme de tableaux de bord, permettant le pilotage de la performance.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Reporting global','d':'Consolidation des données de reporting de l\'ensemble des lots techniques et des thématiques (énergie, eau, déchets, confort, QAI) pour donner une vision d\'ensemble de la performance d\'exploitation du bâtiment.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Rétrocommissioning','d':'Application du processus de commissionnement à un bâtiment existant n\'ayant jamais fait l\'objet d\'un commissionnement initial, visant à identifier et corriger les dysfonctionnements et à optimiser les performances des systèmes en place.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Tableau de bord','d':'Outil de pilotage synthétisant les indicateurs clés de performance d\'exploitation du bâtiment (énergie, eau, déchets, confort, maintenance), permettant au gestionnaire de suivre les objectifs et de déclencher des actions correctives.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Taux de clôture','d':'Indicateur de performance de la maintenance, correspondant au pourcentage d\'ordres de travail (OT) clôturés dans les délais contractuels par rapport au nombre total d\'OT émis sur une période donnée.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Traçabilité des opérations','d':'Enregistrement systématique et exhaustif dans la GMAO de toutes les interventions de maintenance (date, nature, résultat, technicien, pièces utilisées), permettant un suivi historique et une analyse des tendances de défaillance.','c':'MAINTENANCE ET EXPLOITATION'},{'t':'Agriculture biologique','d':'Mode de production agricole excluant l\'utilisation de produits chimiques de synthèse (pesticides, engrais) et d\'OGM, certifié selon le règlement européen (UE) 2018/848. En HQE, la gestion écologique des espaces verts peut s\'appuyer sur les référentiels bio.','c':'GESTION DES DÉCHETS'},{'t':'Bordereau de suivi des déchets (BSD)','d':'Document réglementaire accompagnant le transport des déchets dangereux depuis le producteur jusqu\'au centre de traitement, assurant la traçabilité du déchet et la conformité des filières d\'élimination ou de valorisation.','c':'GESTION DES DÉCHETS'},{'t':'Déchet dangereux','d':'Déchet présentant une ou plusieurs propriétés de danger (inflammable, toxique, corrosif, écotoxique, etc.), soumis à des règles spécifiques de collecte, de transport, de stockage et de traitement (accompagné d\'un BSD).','c':'GESTION DES DÉCHETS'},{'t':'Déchet inerte','d':'Déchet qui ne subit aucune modification physique, chimique ou biologique importante (béton, briques, tuiles, terre non polluée). Il ne se décompose pas et ne pollue pas l\'environnement, mais son enfouissement doit être limité.','c':'GESTION DES DÉCHETS'},{'t':'Déchet non dangereux','d':'Déchet ne présentant pas de propriété de danger au sens de la réglementation, mais nécessitant une gestion appropriée : collecte séparée, tri et orientation vers des filières de valorisation ou d\'élimination autorisées.','c':'GESTION DES DÉCHETS'},{'t':'Déchets d\'activité','d':'Déchets produits par le fonctionnement courant du bâtiment (bureaux, restauration, activités industrielles, commerces) : papier, carton, emballages, déchets alimentaires, etc.','c':'GESTION DES DÉCHETS'},{'t':'Déchets d\'entretien / maintenance','d':'Déchets générés par les opérations de maintenance et d\'entretien du bâtiment et de ses équipements : filtres usagés, fluides, pièces défectueuses, huiles, lampes, etc. Certains sont classés dangereux.','c':'GESTION DES DÉCHETS'},{'t':'Déchets de chantier','d':'Déchets produits lors des travaux de construction, de rénovation ou de démolition : gravats, bois, métaux, plastiques, plâtre, verre, déchets d\'emballage. Soumis aux obligations de tri et de valorisation.','c':'GESTION DES DÉCHETS'},{'t':'Déchets de rénovation','d':'Déchets issus des opérations de rénovation d\'un bâtiment existant, pouvant contenir des substances dangereuses (amiante, plomb, PCB) nécessitant un diagnostic PEMD préalable et des filières de traitement spécifiques.','c':'GESTION DES DÉCHETS'},{'t':'Décret 5 flux (papier/carton, métal, plastique, verre, bois)','d':'Décret n° 2016-288 imposant aux producteurs de déchets professionnels le tri à la source et la collecte séparée de 5 flux de matériaux recyclables : papier/carton, métal, plastique, verre et bois.','c':'GESTION DES DÉCHETS'},{'t':'Décret 7 flux (ajout fractions minérales et plâtre)','d':'Extension du tri 5 flux par le décret n° 2021-821, ajoutant l\'obligation de tri séparé des fractions minérales (béton, briques, tuiles) et du plâtre sur les chantiers de construction et de démolition.','c':'GESTION DES DÉCHETS'},{'t':'Décret 8 flux (ajout textiles)','d':'Extension du tri 7 flux par le décret n° 2022-930, ajoutant l\'obligation de tri séparé des déchets textiles (revêtements de sol, isolation textile, tissus d\'ameublement).','c':'GESTION DES DÉCHETS'},{'t':'Enfouissement','d':'Dépôt définitif de déchets en installation de stockage (anciennement « décharge »), autorisé uniquement pour les déchets non valorisables. La directive européenne 2018/850 vise à réduire progressivement l\'enfouissement.','c':'GESTION DES DÉCHETS'},{'t':'Filière de traitement','d':'Circuit organisé de prise en charge des déchets depuis leur collecte jusqu\'à leur traitement final : valorisation matière (recyclage), valorisation énergétique (incinération avec récupération), compostage ou enfouissement.','c':'GESTION DES DÉCHETS'},{'t':'Incinération','d':'Traitement thermique des déchets par combustion à haute température, permettant de réduire leur volume et, dans les installations équipées, de récupérer l\'énergie produite sous forme de chaleur ou d\'électricité (valorisation énergétique).','c':'GESTION DES DÉCHETS'},{'t':'Pesticides','d':'Substances chimiques destinées à lutter contre les organismes nuisibles (insecticides, herbicides, fongicides). En HQE, leur usage est limité voire interdit dans la gestion des espaces verts du bâtiment (démarche « zéro phyto »).','c':'GESTION DES DÉCHETS'},{'t':'Plan de gestion des déchets','d':'Document organisant la prévention, le tri, la collecte, le transport et le traitement des déchets produits par le bâtiment en exploitation, avec des objectifs de réduction et de valorisation et des indicateurs de suivi.','c':'GESTION DES DÉCHETS'},{'t':'Produits phytosanitaires','d':'Préparations destinées à protéger les végétaux contre les maladies, les ravageurs et les mauvaises herbes. Leur utilisation dans les espaces verts des bâtiments est progressivement restreinte par la réglementation (loi Labbé, plan ECOPHYTO).','c':'GESTION DES DÉCHETS'},{'t':'Registre des déchets','d':'Document obligatoire tenu par le producteur de déchets, enregistrant chronologiquement la nature, la quantité, le mode de collecte et la destination de chaque lot de déchets évacué, assurant la traçabilité.','c':'GESTION DES DÉCHETS'},{'t':'Tri sélectif','d':'Opération de séparation des déchets par catégorie (papier, verre, plastique, organique, dangereux) au moment de leur production, facilitant leur orientation vers les filières de recyclage ou de valorisation appropriées.','c':'GESTION DES DÉCHETS'},{'t':'Valorisation matière','d':'Ensemble des opérations de traitement permettant de récupérer la matière contenue dans les déchets pour la réintroduire dans un cycle de production (recyclage, réemploi), réduisant la consommation de matières premières vierges.','c':'GESTION DES DÉCHETS'},{'t':'Valorisation énergétique','d':'Récupération de l\'énergie contenue dans les déchets lors de leur traitement thermique (incinération, pyrolyse, méthanisation), sous forme de chaleur ou d\'électricité, contribuant au mix énergétique.','c':'GESTION DES DÉCHETS'},{'t':'Accessibilité','d':'Capacité d\'un bâtiment et de ses abords à être utilisés par toutes les personnes, quels que soient leur âge, leur situation de handicap ou leurs capacités physiques, conformément à la réglementation (loi du 11 février 2005).','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Accessibilité universelle','d':'Conception des espaces, équipements et services permettant à l\'ensemble des usagers, y compris les personnes en situation de handicap, d\'accéder, de circuler et d\'utiliser le bâtiment de manière autonome et sans discrimination.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Ascenseur','d':'Appareil élévateur assurant le transport vertical des personnes et des charges entre les étages d\'un bâtiment. Son dimensionnement, sa conformité PMR et sa maintenance sont évalués en HQE.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Autopartage','d':'Service de mise à disposition de véhicules partagés, accessibles en libre-service sur réservation, permettant de réduire le nombre de véhicules individuels et les besoins de stationnement.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Borne de recharge (IRVE)','d':'Infrastructure de Recharge pour Véhicules Électriques, installée sur les parkings du bâtiment. La réglementation impose un pré-équipement d\'un pourcentage de places et l\'installation de bornes opérationnelles.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Covoiturage','d':'Utilisation partagée d\'un véhicule particulier par le conducteur et un ou plusieurs passagers pour un trajet commun, réduisant les émissions de CO₂ par personne et les besoins de stationnement.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Escalator','d':'Escalier mécanique facilitant les déplacements verticaux dans les bâtiments à fort trafic. Sa consommation énergétique et sa maintenance sont prises en compte dans le bilan du bâtiment.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Intermodalité','d':'Utilisation successive de plusieurs modes de transport au cours d\'un même déplacement (marche, vélo, transport en commun, voiture), facilitée par des aménagements de correspondance et d\'information.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Isochrone','d':'Courbe ou zone reliant l\'ensemble des points accessibles depuis un lieu donné en un temps de trajet déterminé. En HQE, les cartes isochrones permettent d\'évaluer la desserte du bâtiment en transports en commun et modes doux.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Mobilité douce','d':'Ensemble des modes de déplacement non motorisés ou à faible impact environnemental : marche à pied, vélo, trottinette, rollers. En HQE, le bâtiment doit proposer des infrastructures favorisant ces modes (stationnements vélo, douches, vestiaires).','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Parking relais','d':'Aire de stationnement située à proximité d\'un nœud de transport en commun (gare, station de métro/tramway), permettant aux automobilistes de garer leur véhicule et de poursuivre leur trajet en transport collectif.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Personne à Mobilité Réduite (PMR)','d':'Toute personne dont la capacité de déplacement est réduite de manière temporaire ou permanente, incluant les personnes en fauteuil roulant, les personnes âgées, les femmes enceintes, les personnes avec poussette ou bagages encombrants.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Plan de Déplacement (PDE / PDIE)','d':'Plan de Déplacements Entreprise ou Inter-Entreprises, ensemble de mesures visant à optimiser les déplacements domicile-travail et professionnels des salariés : covoiturage, vélo, transports en commun, télétravail.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Stationnement vélo','d':'Espace sécurisé et abrité dédié au stationnement des vélos, dimensionné selon le nombre d\'occupants et la réglementation. En HQE, la qualité (arceaux, couverture, éclairage, proximité entrée) et la capacité sont évaluées.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Transport en commun','d':'Mode de transport collectif (bus, tramway, métro, train, car) desservant le bâtiment. En HQE, la proximité et la fréquence des lignes de transport en commun sont des critères d\'évaluation du thème Transports.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Utilisateur en Fauteuil Roulant (UFR)','d':'Personne se déplaçant en fauteuil roulant, nécessitant des aménagements spécifiques : largeurs de passage suffisantes, absence de ressauts, ascenseurs adaptés, places de stationnement réservées et sanitaires accessibles.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Vélo','d':'Mode de déplacement actif et non polluant, encouragé par la réglementation et la certification HQE à travers l\'exigence de stationnements vélo sécurisés, de douches et de vestiaires pour les cyclistes dans les bâtiments tertiaires.','c':'ACCESSIBILITÉ, TRANSPORT ET MOBILITÉ'},{'t':'Amiante','d':'Fibre minérale naturelle cancérogène, interdite en France depuis 1997, encore présente dans de nombreux bâtiments anciens (flocages, calorifugeages, dalles de sol, toitures). Sa gestion est encadrée par le DTA et des protocoles stricts de retrait.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'CREP (Constat de Risque d\'Exposition au Plomb)','d':'Diagnostic obligatoire pour les bâtiments d\'habitation construits avant 1949, mesurant la concentration en plomb des revêtements (peintures). Au-delà du seuil de 1 mg/cm², des travaux de mise en sécurité sont requis.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'DTA (Dossier Technique Amiante)','d':'Document obligatoire pour les bâtiments dont le permis de construire est antérieur au 1er juillet 1997, identifiant et localisant les matériaux contenant de l\'amiante, leur état de conservation et les mesures de gestion préconisées.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Désenfumage','d':'Système de sécurité incendie permettant l\'évacuation des fumées et des gaz chauds hors du bâtiment en cas de sinistre, par des dispositifs naturels (exutoires) ou mécaniques (ventilateurs de désenfumage), facilitant l\'évacuation et l\'intervention des secours.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'ERP (Établissement Recevant du Public)','d':'Bâtiment ou local dans lequel des personnes extérieures sont admises, classé par type d\'activité et par catégorie selon la capacité d\'accueil. Les ERP sont soumis à des règles spécifiques de sécurité incendie, d\'accessibilité et de QAI.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'ICPE (Installation Classée pour la Protection de l\'Environnement)','d':'Installation industrielle ou agricole susceptible de générer des risques ou des nuisances pour l\'environnement ou le voisinage, soumise à un régime de déclaration, d\'enregistrement ou d\'autorisation préfectorale.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'IGH (Immeuble de Grande Hauteur)','d':'Bâtiment dont le plancher bas du dernier niveau est situé à plus de 50 m pour les habitations ou 28 m pour les autres usages. Les IGH sont soumis à des règles de sécurité renforcées (compartimentage, désenfumage, colonnes sèches, etc.).','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Inondation','d':'Submersion temporaire par l\'eau de terrains habituellement hors d\'eau, pouvant affecter le bâtiment par débordement de cours d\'eau, ruissellement urbain ou remontée de nappe. Le risque est cartographié par les PPRI.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Plomb','d':'Métal lourd toxique affectant le système nerveux, le développement intellectuel des enfants (saturnisme) et les reins. Présent dans les peintures anciennes (céruse) et certaines canalisations d\'eau, il fait l\'objet de diagnostics obligatoires (CREP).','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'PPR (Plan de Prévention des Risques)','d':'Document réglementaire délimitant les zones exposées aux risques naturels ou technologiques et prescrivant les mesures de prévention, de protection et de sauvegarde à appliquer. Annexé au PLU, il s\'impose aux autorisations d\'urbanisme.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'PPRI (Plan de Prévention des Risques d\'Inondation)','d':'PPR spécifique au risque d\'inondation, cartographiant les zones inondables et définissant les prescriptions constructives (cotes de référence, transparence hydraulique, matériaux résistants à l\'eau) pour les projets situés en zone à risque.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Retrait-gonflement des argiles','d':'Phénomène géotechnique affectant les sols argileux qui se rétractent en période de sécheresse et gonflent lors de la réhumidification, provoquant des mouvements de terrain pouvant endommager les fondations et les structures des bâtiments.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Risque naturel','d':'Aléa d\'origine naturelle (inondation, séisme, glissement de terrain, tempête, canicule, feu de forêt) susceptible de porter atteinte aux personnes, aux biens ou à l\'environnement. Son évaluation est intégrée dans la démarche HQE.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Risque sanitaire','d':'Probabilité de survenue d\'effets néfastes sur la santé des occupants, liés à des facteurs du bâtiment : qualité de l\'air (amiante, radon, COV), qualité de l\'eau (légionelles, plomb), ondes électromagnétiques, bruit.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Risque technologique','d':'Aléa lié à la proximité d\'installations industrielles dangereuses (ICPE Seveso), de réseaux de transport de matières dangereuses ou d\'infrastructures à risque, pris en compte dans les études de site du projet.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Saturnisme','d':'Intoxication par le plomb, principalement liée à l\'ingestion de poussières ou d\'écailles de peintures au plomb dans les bâtiments anciens. Les enfants sont particulièrement vulnérables. Le CREP vise à prévenir ce risque.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Sprinkler','d':'Système d\'extinction automatique à eau composé de têtes d\'aspersion se déclenchant individuellement sous l\'effet de la chaleur, protégeant les locaux contre l\'incendie par l\'arrosage de la zone sinistrée.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'SSI (Système de Sécurité Incendie)','d':'Ensemble des équipements de détection, d\'alarme, de mise en sécurité et de désenfumage d\'un bâtiment, organisé en catégories (A à E) selon le niveau de protection requis par la réglementation incendie.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Séisme','d':'Vibrations du sol causées par la rupture brutale de roches en profondeur. Les bâtiments en zone sismique doivent respecter les règles de construction parasismique (Eurocodes 8), avec des dispositions sur les fondations et la structure.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Sûreté / Intrusion','d':'Ensemble des dispositifs et mesures de protection du bâtiment contre les actes de malveillance : contrôle d\'accès, vidéosurveillance, détection d\'intrusion, éclairage de sécurité, organisation des circulations.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Termites','d':'Insectes xylophages se nourrissant de bois et de cellulose, pouvant gravement endommager les structures en bois des bâtiments. Un diagnostic termites est obligatoire avant la vente d\'un bien situé dans une zone à risque.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Vidéosurveillance','d':'Système de surveillance par caméras permettant la visualisation et l\'enregistrement d\'images pour la sécurité des personnes et des biens, soumis à déclaration (CNIL) et aux exigences de la loi Informatique et Libertés.','c':'RISQUES NATURELS ET SANITAIRES'},{'t':'Acousticien','d':'Ingénieur spécialisé dans l\'étude, la conception et le contrôle des performances acoustiques des bâtiments : isolement aux bruits aériens et d\'impact, correction acoustique des locaux, traitement des bruits d\'équipements.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'ADEME','d':'Agence de la Transition Écologique (anciennement Agence de l\'Environnement et de la Maîtrise de l\'Énergie). Établissement public accompagnant les acteurs dans leurs démarches de transition énergétique et écologique. Développe des outils et méthodologies de référence (Bilan Carbone, AEU, fiches CBS).','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'AFNOR','d':'Association Française de Normalisation, organisme national de normalisation élaborant et publiant les normes françaises (NF) et représentant la France au sein des instances européennes (CEN) et internationales (ISO).','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'AICVF','d':'Association des Ingénieurs et techniciens en Climatique, Ventilation et Froid. Publie des guides techniques de référence pour la conception et le dimensionnement des installations de génie climatique dans les bâtiments.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'ANSES','d':'Agence Nationale de Sécurité Sanitaire de l\'alimentation, de l\'environnement et du travail. Évalue les risques sanitaires liés aux substances chimiques, aux ondes électromagnétiques et aux contaminants biologiques présents dans l\'environnement intérieur.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'ARS (Agence Régionale de Santé)','d':'Autorité sanitaire régionale chargée du pilotage de la politique de santé publique, incluant le contrôle de la qualité de l\'eau, la surveillance du risque légionelles et la gestion des alertes sanitaires liées aux bâtiments.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Assistant à Maîtrise d\'Ouvrage (AMO)','d':'Professionnel ou organisme accompagnant le maître d\'ouvrage dans la définition de ses besoins, le pilotage du projet et le suivi des performances. En HQE, l\'AMO environnemental guide la démarche de certification.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'BET Fluides','d':'Bureau d\'Études Techniques spécialisé dans la conception des installations de chauffage, ventilation, climatisation, plomberie et désenfumage (lots CVC et plomberie), assurant le dimensionnement et le respect des performances.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'BRGM (Bureau de Recherches Géologiques et Minières)','d':'Établissement public de référence dans le domaine des sciences de la Terre, fournissant les données géologiques, les cartes de risques naturels (argiles, séismes, cavités) et l\'expertise hydrogéologique pour les projets de construction.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Bureau d\'études','d':'Structure d\'ingénierie réalisant les études techniques nécessaires à la conception et à la réalisation d\'un projet de bâtiment : structure, thermique, acoustique, fluides, électricité, environnement, etc.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'CEREMA','d':'Centre d\'Études et d\'Expertise sur les Risques, l\'Environnement, la Mobilité et l\'Aménagement. Établissement public apportant son expertise technique aux collectivités et à l\'État, notamment en matière de performance énergétique et de CPE.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Cerqual','d':'Filiale du groupe Qualitel spécialisée dans la certification de la qualité des logements neufs et existants, délivrant les certifications NF Habitat, NF Habitat HQE et Patrimoine Habitat.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Certivea','d':'Filiale du CSTB délivrant les certifications HQE pour les bâtiments non résidentiels (tertiaire, commerces, enseignement, santé) et les certifications NF HQE Bâtiments Tertiaires et HQE BD.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'COFRAC','d':'Comité Français d\'Accréditation, seul organisme habilité à accréditer les laboratoires d\'essais et d\'analyses en France, garantissant la fiabilité des résultats de mesure (QAI, acoustique, énergie, eau, etc.).','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Commissaire de justice (anciennement huissier)','d':'Officier public et ministériel pouvant être sollicité pour constater officiellement l\'état d\'un bâtiment, les nuisances de chantier, les résultats d\'essais ou tout fait nécessitant une preuve juridique opposable.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'COSTIC','d':'Comité Scientifique et Technique des Industries Climatiques. Centre technique spécialisé dans les équipements de génie climatique, publiant des guides et des études techniques de référence pour les professionnels du CVC.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'CSTB','d':'Centre Scientifique et Technique du Bâtiment. Établissement public de recherche et d\'expertise au service de l\'innovation dans la construction, évaluant les produits innovants (Avis Techniques) et développant les référentiels de certification HQE.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Exploitant','d':'Personne physique ou morale assurant le fonctionnement quotidien des installations techniques du bâtiment : conduite des équipements, surveillance des paramètres, interventions de maintenance de premier niveau.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Gestionnaire','d':'Personne physique ou morale responsable de la gestion globale d\'un bâtiment ou d\'un patrimoine immobilier, coordonnant les aspects techniques, financiers et administratifs de l\'exploitation et de la maintenance.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'GIEC (Groupe Intergouvernemental sur l\'Évolution du Climat)','d':'Organisme des Nations Unies évaluant l\'état des connaissances scientifiques sur le changement climatique, ses impacts et les stratégies d\'atténuation et d\'adaptation. Ses rapports servent de référence pour les politiques climatiques.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'HCSP (Haut Conseil de la Santé Publique)','d':'Instance d\'expertise française fournissant des avis et recommandations sur les questions de santé publique, incluant les valeurs guides de la qualité de l\'air intérieur et les seuils d\'exposition aux polluants.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Maîtrise d\'Ouvrage (MOA)','d':'Personne physique ou morale pour le compte de laquelle l\'ouvrage est réalisé. Le maître d\'ouvrage définit les objectifs du projet, le programme, le budget et les exigences de performance, et porte la démarche de certification HQE.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Maîtrise d\'Œuvre (MOE)','d':'Personne physique ou morale chargée de la conception architecturale et technique du projet et du suivi de sa réalisation (architecte, bureaux d\'études). La MOE traduit les exigences du programme en solutions techniques conformes.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Occupant / Utilisateur','d':'Personne utilisant le bâtiment au quotidien (salarié, résident, visiteur). En HQE, la satisfaction, le confort et la santé des occupants sont des objectifs centraux, et leur sensibilisation aux bonnes pratiques est évaluée.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'OMS (Organisation Mondiale de la Santé)','d':'Agence des Nations Unies définissant les normes et recommandations internationales en matière de santé publique, incluant les valeurs guides pour la qualité de l\'air intérieur et la qualité de l\'eau potable.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Organisme certificateur','d':'Entité accréditée et indépendante délivrant les certifications HQE après vérification de la conformité du bâtiment aux exigences du référentiel. En France, Certivea pour le tertiaire et Cerqual pour le logement.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Prestataire d\'entretien','d':'Entreprise assurant les opérations de nettoyage, de propreté et d\'entretien courant du bâtiment et de ses espaces verts, contribuant au maintien des conditions d\'hygiène et de confort des occupants.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Prestataire de maintenance','d':'Entreprise spécialisée assurant les opérations de maintenance préventive et corrective des installations techniques du bâtiment (CVC, électricité, plomberie, ascenseurs), selon les gammes et fréquences définies dans le plan de maintenance.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'REHVA','d':'Federation of European Heating, Ventilation and Air Conditioning Associations. Fédération européenne regroupant les associations nationales de CVC, publiant des guides techniques et des recommandations pour la conception des installations.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Thermicien','d':'Ingénieur spécialisé dans les études thermiques et énergétiques des bâtiments : calculs réglementaires (RE2020), simulation thermique dynamique, dimensionnement des systèmes de chauffage, rafraîchissement et production d\'ECS.','c':'ACTEURS ET PARTIES PRENANTES'},{'t':'Audit de certification','d':'Vérification réalisée par l\'organisme certificateur (Certivea, Cerqual) pour évaluer la conformité du bâtiment aux exigences du référentiel HQE, sur la base des pièces justificatives et éventuellement d\'une visite sur site.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Axe Bâtiment','d':'Volet de la certification HQE évaluant les caractéristiques intrinsèques du bâtiment (conception, matériaux, équipements, performances mesurées), par opposition à l\'axe Gestion qui porte sur l\'exploitation.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Axe Gestion','d':'Volet de la certification HQE évaluant la qualité de la gestion et de l\'exploitation du bâtiment : pilotage de la performance, maintenance, suivi des consommations, amélioration continue.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Cas de non-applicabilité','d':'Situation dans laquelle une exigence du référentiel HQE ne peut pas être évaluée car elle n\'est pas pertinente pour le bâtiment concerné (exemple : pas de parking, donc l\'exigence IRVE ne s\'applique pas). Les points correspondants sont redistribués.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Dérogation','d':'Autorisation exceptionnelle accordée par l\'organisme certificateur de ne pas respecter une exigence spécifique, sous réserve de justification technique et de mise en œuvre de mesures compensatoires.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Exigence (SCORED)','d':'Critère évaluable du référentiel HQE auquel est attribué un nombre de points selon le niveau de performance atteint. Les exigences SCORED sont notées de 0 à un maximum variable, contribuant au score total du thème.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Mode de preuve','d':'Document ou élément justificatif permettant de démontrer la conformité à une exigence HQE : rapport d\'études, attestation, mesure in situ, plan, constat d\'huissier, facture, rapport de commissioning, etc.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Niveau de certification (Bon, Très Bon, Excellent, Exceptionnel)','d':'Échelle de reconnaissance de la performance globale du bâtiment en certification HQE, attribuée en fonction du pourcentage de points obtenus par rapport aux points disponibles dans l\'ensemble des thèmes.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Non-applicabilité','d':'Déclaration attestant qu\'une exigence du référentiel ne peut être évaluée pour le bâtiment en raison de sa configuration, de son usage ou de son contexte. Les points non applicables sont soustraits du total des points disponibles.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Phase Conception','d':'Étape du projet de construction ou de rénovation au cours de laquelle les choix architecturaux, techniques et environnementaux sont définis. En HQE, les modes de preuve en phase conception sont des documents d\'études et de prescriptions.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Phase Exploitation','d':'Période de vie du bâtiment après sa mise en service, pendant laquelle il est occupé, exploité et maintenu. En HQE BD, les exigences d\'exploitation portent sur le suivi des performances, la maintenance et l\'amélioration continue.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Phase Réalisation','d':'Étape d\'exécution des travaux de construction ou de rénovation, pendant laquelle les prescriptions de conception sont mises en œuvre. Les modes de preuve incluent les PV d\'essais, les rapports de chantier et les DOE.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Points disponibles','d':'Nombre total de points pouvant être obtenus dans un thème ou dans l\'ensemble du référentiel HQE, correspondant à la somme des points maximaux de chaque exigence applicable.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Points non applicables','d':'Points correspondant aux exigences déclarées non applicables pour le bâtiment, soustraits du total des points disponibles pour le calcul du pourcentage de performance.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Points vérifiés a minima','d':'Seuil minimal de points devant être justifiés dans certains thèmes pour garantir une couverture suffisante des enjeux, indépendamment du score global atteint.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Profil environnemental','d':'Représentation graphique synthétisant les scores obtenus par le bâtiment dans chaque thème HQE, permettant de visualiser rapidement les points forts et les axes d\'amélioration.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Prérequis (PR)','d':'Exigence minimale obligatoire du référentiel HQE devant être satisfaite pour obtenir la certification, quel que soit le niveau visé. Le non-respect d\'un prérequis bloque la certification.','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Seuil de certification','d':'Pourcentage minimal de points devant être atteint, par thème et globalement, pour obtenir un niveau de certification donné (Bon, Très Bon, Excellent, Exceptionnel).','c':'PHASES ET PROCESSUS DE CERTIFICATION'},{'t':'Code de l\'Environnement','d':'Recueil de textes législatifs et réglementaires régissant le droit de l\'environnement en France : prévention des pollutions, protection de la nature, gestion des déchets, risques naturels, énergie, eau, air, bruit, ICPE.','c':'URBANISME ET AMÉNAGEMENT'},{'t':'Code de l\'Urbanisme','d':'Ensemble des dispositions législatives et réglementaires encadrant l\'aménagement du territoire, la planification urbaine (PLU, SCoT), les autorisations de construire et les règles d\'occupation des sols en France.','c':'URBANISME ET AMÉNAGEMENT'},{'t':'Code de la Construction et de l\'Habitation','d':'Code regroupant les règles relatives à la construction des bâtiments (sécurité, accessibilité, performance énergétique, habitabilité) et à l\'habitat (logement social, copropriété, baux).','c':'URBANISME ET AMÉNAGEMENT'},{'t':'PCAET (Plan Climat-Air-Énergie Territorial)','d':'Outil de planification stratégique des collectivités territoriales de plus de 20 000 habitants, définissant les objectifs et actions en matière de réduction des émissions de GES, d\'adaptation au changement climatique et de qualité de l\'air.','c':'URBANISME ET AMÉNAGEMENT'},{'t':'PLU (Plan Local d\'Urbanisme)','d':'Document de planification urbaine communal ou intercommunal définissant les règles d\'utilisation des sols : zones constructibles, règles de hauteur, d\'implantation, de densité, de stationnement et d\'espaces verts.','c':'URBANISME ET AMÉNAGEMENT'},{'t':'SCoT (Schéma de Cohérence Territoriale)','d':'Document de planification à l\'échelle intercommunale ou d\'un bassin de vie, fixant les orientations d\'aménagement du territoire en matière d\'urbanisme, de déplacements, d\'environnement et d\'habitat pour une durée de 20 ans.','c':'URBANISME ET AMÉNAGEMENT'},{'t':'Accord de Paris (COP21, 2015)','d':'Traité international adopté lors de la COP21 engageant 196 pays à limiter le réchauffement climatique à +2°C (objectif +1,5°C) par rapport à l\'ère préindustrielle, en réduisant leurs émissions de gaz à effet de serre.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Directive RoHS (substances dangereuses dans les équipements électroniques)','d':'Directive européenne 2011/65/UE restreignant l\'utilisation de substances dangereuses (plomb, mercure, cadmium, chrome hexavalent, PBB, PBDE) dans les équipements électriques et électroniques.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Protocole de Kyoto (1997)','d':'Premier accord international juridiquement contraignant de réduction des émissions de GES, adopté en 1997 sous l\'égide de l\'ONU. Il a imposé des objectifs chiffrés aux pays industrialisés et introduit les mécanismes de marché carbone.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Protocole de Montréal (substances appauvrissant la couche d\'ozone)','d':'Traité international de 1987 visant à éliminer progressivement les substances appauvrissant la couche d\'ozone (CFC, HCFC), étendu par l\'amendement de Kigali (2016) aux HFC à fort pouvoir de réchauffement global.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Règlement F-Gas / F-Gaz (fluides frigorigènes, Règlement UE 517/2014)','d':'Règlement européen encadrant l\'utilisation des gaz à effet de serre fluorés (HFC, PFC, SF6) utilisés dans les systèmes de climatisation et de réfrigération, imposant un calendrier de réduction progressive (phase-down) et des obligations de contrôle des fuites.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Règlement REACH (CE n° 1907/2006 — substances chimiques)','d':'Règlement européen d\'enRegistrement, d\'Évaluation, d\'Autorisation et de restriction des substances CHimiques, visant à protéger la santé humaine et l\'environnement en imposant aux fabricants et importateurs de substances chimiques de démontrer leur innocuité.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'CFC (Chlorofluorocarbures)','d':'Gaz synthétiques autrefois utilisés comme fluides frigorigènes et propulseurs d\'aérosols, responsables de la destruction de la couche d\'ozone. Totalement interdits par le Protocole de Montréal depuis 2010.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Fluides frigorigènes','d':'Substances utilisées dans les circuits des systèmes de climatisation et de réfrigération pour transférer la chaleur par changement de phase (évaporation/condensation). Leur impact environnemental (ODP, GWP) est encadré par le règlement F-Gas.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'HCFC (Hydrochlorofluorocarbures)','d':'Fluides frigorigènes de transition ayant remplacé les CFC, mais contribuant encore à la destruction de la couche d\'ozone et au réchauffement climatique. Leur utilisation est interdite dans les équipements neufs depuis 2010 en Europe.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'HFC (Hydrofluorocarbures)','d':'Fluides frigorigènes ne détruisant pas la couche d\'ozone mais ayant un fort potentiel de réchauffement global (PRG jusqu\'à 14 800 pour le R-23). Soumis au règlement F-Gas imposant une réduction progressive de 79 % entre 2015 et 2030.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Substances appauvrissant la couche d\'ozone (SAO)','d':'Ensemble des composés chimiques (CFC, HCFC, halons, bromure de méthyle) qui détruisent la couche d\'ozone stratosphérique protégeant la Terre des rayons UV. Leur élimination est régie par le Protocole de Montréal.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Loi AGEC (Anti-Gaspillage pour une Économie Circulaire)','d':'Loi n° 2020-105 du 10 février 2020 visant à transformer le modèle de production et de consommation : interdiction de destruction des invendus, obligation d\'information sur la réparabilité, extension du tri et du réemploi.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Loi Climat et Résilience','d':'Loi n° 2021-1104 du 22 août 2021 portant diverses mesures de lutte contre le changement climatique et de renforcement de la résilience, incluant des dispositions sur la rénovation énergétique, l\'artificialisation des sols et la mobilité durable.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Loi de Transition Énergétique pour la Croissance Verte (LTECV)','d':'Loi n° 2015-992 du 17 août 2015 fixant les grands objectifs de la politique énergétique française : réduction de 40 % des GES d\'ici 2030, 32 % d\'EnR dans la consommation finale, réduction de 50 % de la consommation d\'énergie d\'ici 2050.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Loi ELAN (Évolution du Logement, de l\'Aménagement et du Numérique)','d':'Loi n° 2018-1021 du 23 novembre 2018 portant réformes du logement et de l\'aménagement, incluant des dispositions sur la performance énergétique (décret tertiaire), le carnet numérique du logement et l\'accessibilité.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Loi Grenelle I et II','d':'Lois n° 2009-967 et 2010-788 issues du Grenelle de l\'Environnement, fixant des objectifs ambitieux en matière de performance énergétique des bâtiments (BBC pour les constructions neuves), de biodiversité, de transports et de gouvernance environnementale.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Plan ECOPHYTO','d':'Plan national visant à réduire l\'utilisation des produits phytosanitaires (pesticides) en France, avec un objectif de réduction de 50 %. Il impacte la gestion des espaces verts des bâtiments en encourageant les alternatives non chimiques.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'RE2020 (Réglementation Environnementale 2020)','d':'Réglementation applicable aux constructions neuves depuis 2022, remplaçant la RT2012. Elle renforce les exigences de performance énergétique (Bbio, Cep, Cep,nr), introduit un seuil maximal d\'émissions de carbone (Ic) et impose le confort d\'été (DH).','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'RT2012 (Réglementation Thermique 2012)','d':'Ancienne réglementation thermique imposant un Bbio maximal, un Cep de 50 kWhEP/m².an modulé et un confort d\'été. Remplacée par la RE2020 pour les constructions neuves, elle reste applicable aux bâtiments existants sous certaines conditions.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Code de l\'Environnement','d':'Recueil de textes régissant le droit de l\'environnement en France : pollutions, risques, déchets, eau, air, nature, énergie, ICPE. Base juridique de nombreuses obligations environnementales du bâtiment.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Code de l\'Urbanisme','d':'Ensemble des dispositions régissant l\'aménagement du territoire, les documents de planification (PLU, SCoT) et les autorisations de construire.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Code de l\'Énergie','d':'Code regroupant les dispositions relatives à la politique énergétique française : maîtrise de la demande, développement des EnR, marchés de l\'énergie, réseaux, stockage, obligations d\'économies d\'énergie (CEE).','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Code de la Construction et de l\'Habitation','d':'Code réglementant la construction (règles techniques, sécurité, accessibilité, performance énergétique) et l\'habitat (logement social, copropriété, baux, décence).','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Code de la Santé Publique','d':'Code regroupant les dispositions relatives à la santé publique, incluant la qualité de l\'eau potable, la prévention du risque légionelles, les valeurs limites d\'exposition aux polluants et la lutte contre le saturnisme.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Code du Travail','d':'Code régissant les relations de travail, incluant les prescriptions relatives à la santé et à la sécurité des travailleurs : ventilation des locaux, éclairage, bruit, température, amiante, DIUO.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Directive 2008/98/CE (déchets)','d':'Directive-cadre européenne sur les déchets établissant la hiérarchie de gestion (prévention, réemploi, recyclage, valorisation, élimination) et imposant aux États membres des objectifs de valorisation.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Directive 2010/31/UE (performance énergétique des bâtiments)','d':'Directive européenne imposant que tous les bâtiments neufs soient « à consommation d\'énergie quasi nulle » (NZEB) à partir de 2021, et fixant un cadre pour la certification énergétique (DPE).','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Directive 2012/27/UE (efficacité énergétique)','d':'Directive européenne fixant un cadre de mesures pour améliorer l\'efficacité énergétique de l\'UE : obligation d\'audits énergétiques, rénovation des bâtiments publics, comptage individuel, schémas d\'obligations.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Directive 2013/35/UE (champs électromagnétiques)','d':'Directive européenne fixant les prescriptions minimales de sécurité et de santé relatives à l\'exposition des travailleurs aux champs électromagnétiques, définissant des valeurs limites d\'exposition et des valeurs déclenchant l\'action.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Directive 2018/850 (mise en décharge)','d':'Directive européenne limitant progressivement la mise en décharge des déchets recyclables et valorisables, avec un objectif de réduction à 10 % des déchets municipaux mis en décharge d\'ici 2035.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Règlement (CE) n° 1907/2006 (REACH)','d':'Règlement européen sur l\'enregistrement, l\'évaluation, l\'autorisation et la restriction des substances chimiques, imposant aux fabricants de démontrer la sécurité de leurs substances pour la santé et l\'environnement.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Règlement (UE) 2018/848 (production biologique)','d':'Règlement européen définissant les règles de production, d\'étiquetage et de contrôle des produits issus de l\'agriculture biologique, applicable aux espaces verts gérés selon des pratiques biologiques.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Règlement (UE) 517/2014 (F-Gas — gaz à effet de serre fluorés)','d':'Règlement européen imposant une réduction progressive des quantités de HFC mises sur le marché (phase-down de 79 % entre 2015 et 2030), des obligations de contrôle des fuites et de qualification des opérateurs.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Règlement européen 889/2008 (agriculture biologique)','d':'Ancien règlement d\'application de l\'agriculture biologique (remplacé par le règlement 2018/848), détaillant les règles de production, de transformation et d\'étiquetage des produits bio.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 10 avril 2020 (dispositif Éco-énergie tertiaire)','d':'Arrêté fixant les modalités d\'application du décret tertiaire : obligations de réduction des consommations d\'énergie finale des bâtiments tertiaires de plus de 1 000 m² (-40 % en 2030, -50 % en 2040, -60 % en 2050).','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 10 octobre 2012 (valeurs guide QAI)','d':'Arrêté définissant les valeurs guides pour la qualité de l\'air intérieur dans les ERP : formaldéhyde (30 µg/m³ objectif cible) et benzène (2 µg/m³ objectif cible).','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 12 juillet 2011 (diagnostic amiante)','d':'Arrêté précisant les conditions de réalisation du diagnostic amiante dans les bâtiments, les matériaux à rechercher et les modalités de rédaction du DTA.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 13 avril 2017 (acoustique bâtiments existants)','d':'Arrêté fixant les exigences acoustiques applicables lors de la rénovation de bâtiments existants d\'habitation, de santé et d\'enseignement.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 1er février 2010 (surveillance des légionelles)','d':'Arrêté imposant la surveillance régulière de la qualité de l\'eau dans les réseaux des ERP vis-à-vis du risque légionelles : analyses périodiques, carnet sanitaire, entretien des installations.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 21 décembre 2021 (sortie du statut de déchet)','d':'Arrêté définissant les conditions dans lesquelles certains déchets cessent d\'être considérés comme tels et deviennent des matières premières secondaires pouvant être réutilisées.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 21 juillet 2015 (installations électriques)','d':'Arrêté relatif à la vérification des installations électriques dans les ERP, fixant les fréquences de contrôle et les prescriptions de sécurité.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 22 juillet 2020 (retrait-gonflement des argiles)','d':'Arrêté définissant les techniques de construction adaptées aux zones exposées au retrait-gonflement des argiles : fondations, drainage, gestion de la végétation à proximité.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 22 juin 2007 (légionelles)','d':'Arrêté fixant les prescriptions techniques de prévention du risque légionelles dans les installations de production et de distribution d\'eau chaude sanitaire des ERP.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 24 mars 1982 (aération des bâtiments d\'habitation)','d':'Arrêté fondateur fixant les débits minimaux de renouvellement d\'air dans les logements, selon le nombre de pièces principales, définissant les règles de base de la ventilation résidentielle.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 24 novembre 2020 (étiquetage émissions COV)','d':'Arrêté actualisant les modalités d\'étiquetage des produits de construction et de décoration selon leurs émissions de COV dans l\'air intérieur (classes A+, A, B, C).','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 25 avril 2003 (limitation du bruit — hôtels, enseignement)','d':'Arrêté fixant les exigences acoustiques applicables aux bâtiments d\'hôtellerie et d\'enseignement : isolement aux bruits aériens, bruits d\'impact, bruits d\'équipements.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 26 mars 2023 (audit énergétique)','d':'Arrêté définissant le contenu et les modalités de réalisation de l\'audit énergétique obligatoire lors de la vente de logements classés F et G au DPE.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 30 juin 2022 (RE2020 tertiaire)','d':'Arrêté étendant les exigences de la RE2020 aux bâtiments tertiaires (bureaux et enseignement), fixant les seuils de Bbio, Cep, Cep,nr, Ic et DH pour ces catégories.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 30 mai 1996 (classement infrastructures de transport terrestre)','d':'Arrêté classant les infrastructures de transport terrestre en fonction de leur niveau sonore, déterminant les zones de bruit et les prescriptions d\'isolement acoustique des bâtiments riverains.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 31 mai 2021 (RE2020)','d':'Arrêté fondateur de la RE2020 pour les bâtiments résidentiels, fixant les exigences de résultats (Bbiomax, Cepmax, Cep,nrmax, Icmax, DHmax) et les méthodes de calcul.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 4 juin 2021 (RE2020 résidentiel)','d':'Arrêté complétant les prescriptions de la RE2020 pour le résidentiel, précisant les modalités de calcul et les valeurs de modulation des seuils.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 7 septembre 2009 (bâtiments existants — assainissement)','d':'Arrêté fixant les prescriptions techniques applicables aux installations d\'assainissement non collectif des bâtiments existants.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 8 février 2012 (surveillance QAI dans les ERP)','d':'Arrêté rendant obligatoire la surveillance de la qualité de l\'air intérieur dans certains ERP accueillant des enfants (crèches, écoles, collèges), avec des campagnes de mesure du formaldéhyde, du benzène et du CO₂.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Arrêté du 8 octobre 1987 (contrôle périodique des installations d\'aération)','d':'Arrêté imposant le contrôle périodique des installations de ventilation et d\'aération dans les établissements recevant des travailleurs, vérifiant les débits d\'air et l\'état des filtres.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2002-775 (valeurs limites exposition champs EM)','d':'Décret fixant les valeurs limites d\'exposition du public aux champs électromagnétiques (0 Hz à 300 GHz), transposant la recommandation européenne 1999/519/CE.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2007-1467 (livre V code environnement, ICPE)','d':'Décret relatif à la nomenclature des ICPE, classant les installations selon les risques ou nuisances qu\'elles présentent et les soumettant à déclaration, enregistrement ou autorisation.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2011-321 (étiquetage sanitaire produits construction)','d':'Décret rendant obligatoire l\'étiquetage des produits de construction et de décoration selon leurs émissions de polluants volatils (classes A+, A, B, C), applicable depuis 2012.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2012-14 (surveillance QAI dans les ERP)','d':'Décret imposant la surveillance de la qualité de l\'air intérieur dans les ERP accueillant des populations sensibles, avec un calendrier progressif selon la catégorie d\'établissement.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2016-1074 (prévention légionelles)','d':'Décret renforçant les obligations de surveillance et de prévention du risque légionelles dans les réseaux d\'eau des ERP : analyses régulières, carnet sanitaire, seuils d\'action et d\'alerte.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2016-288 (tri 5 flux)','d':'Décret imposant le tri à la source et la collecte séparée de 5 flux de déchets recyclables (papier/carton, métal, plastique, verre, bois) par les producteurs de déchets non ménagers.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2019-771 (obligations tertiaire — Éco-énergie)','d':'Décret tertiaire imposant aux bâtiments de plus de 1 000 m² de surface à usage tertiaire de réduire leur consommation d\'énergie finale de 40 % en 2030, 50 % en 2040 et 60 % en 2050 par rapport à une année de référence.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2021-1004 (déchet et économie circulaire)','d':'Décret d\'application de la loi AGEC précisant les obligations en matière de gestion des déchets, de réemploi, de recyclage et d\'information du consommateur sur la durabilité des produits.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2021-321 (diagnostic PEMD)','d':'Décret rendant obligatoire le diagnostic PEMD (Produits, Équipements, Matériaux, Déchets) avant les opérations de démolition ou de rénovation significative, pour favoriser le réemploi et la valorisation.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2021-821 (tri 7 flux)','d':'Décret étendant le tri 5 flux à 7 flux en ajoutant les fractions minérales (béton, briques, tuiles) et le plâtre pour les déchets de construction et de démolition.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2022-1690 (RE2020)','d':'Décret modifiant certaines dispositions de la RE2020, ajustant les seuils et les modalités d\'application pour les différentes catégories de bâtiments neufs.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2022-1720 (audit énergétique)','d':'Décret rendant obligatoire l\'audit énergétique lors de la vente de maisons individuelles et d\'immeubles en mono-propriété classés F ou G au DPE.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Décret n° 2022-930 (tri 8 flux — textiles)','d':'Décret ajoutant les textiles comme 8e flux de tri obligatoire pour les déchets professionnels, incluant les moquettes, les revêtements textiles et les tissus d\'ameublement.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'DTU (Documents Techniques Unifiés)','d':'Ensemble de normes françaises définissant les conditions de mise en œuvre des ouvrages du bâtiment (maçonnerie, charpente, plomberie, etc.), servant de référence pour les marchés de travaux et les contrôles de conformité.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Eurocodes (normes européennes de calcul de structures)','d':'Ensemble de normes européennes harmonisées pour le dimensionnement des structures de bâtiments et de génie civil, couvrant les charges, le béton armé, l\'acier, le bois, la maçonnerie, le géotechnique et le parasismique.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'FDX 60-000 (maintenance industrielle — niveaux de maintenance, AFNOR)','d':'Fascicule de documentation AFNOR définissant les quatre niveaux de maintenance en fonction de la complexité des interventions, des compétences requises et des moyens nécessaires.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'FDX 60-090 (critères de choix du type de contrat de maintenance)','d':'Fascicule de documentation AFNOR guidant le choix du type de contrat de maintenance (moyens, résultat, forfait, régie) selon les objectifs du maître d\'ouvrage et la nature des installations.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'ISO 14001 (management environnemental)','d':'Norme internationale spécifiant les exigences d\'un système de management environnemental, permettant à une organisation de maîtriser ses impacts sur l\'environnement et d\'améliorer continuellement sa performance.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'ISO 14091 (adaptation au changement climatique)','d':'Norme internationale fournissant les lignes directrices pour l\'évaluation de la vulnérabilité, des impacts et des risques liés au changement climatique, et pour l\'identification des mesures d\'adaptation.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'ISO 15686 (durée de vie des bâtiments)','d':'Série de normes internationales définissant les méthodes de prévision de la durée de vie des bâtiments et de leurs composants, utilisées pour la planification de la maintenance et l\'analyse en coût global.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'ISO 16000 (air intérieur — mesurage)','d':'Série de normes internationales définissant les méthodes de prélèvement et d\'analyse des polluants de l\'air intérieur : formaldéhyde (ISO 16000-3), COV (ISO 16000-6), particules, radon, etc.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'ISO 16890 (filtres à air — classification)','d':'Norme internationale classant les filtres à air selon leur efficacité de capture des particules fines (ePM1, ePM2,5, ePM10), remplaçant l\'ancienne norme EN 779.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'ISO 20887 (conception pour la démontabilité et l\'adaptabilité)','d':'Norme internationale fournissant les principes de conception facilitant le démontage, le réemploi, le recyclage et l\'adaptabilité des bâtiments et de leurs composants en fin de vie.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'ISO 50001 (management de l\'énergie)','d':'Norme internationale spécifiant les exigences d\'un système de management de l\'énergie, permettant d\'améliorer systématiquement la performance énergétique d\'une organisation : planification, mise en œuvre, vérification, amélioration.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN 12464-1 (éclairage des lieux de travail intérieurs)','d':'Norme européenne fixant les exigences d\'éclairage artificiel des espaces de travail intérieurs : niveaux d\'éclairement maintenus, uniformité, UGR limite, rendu des couleurs, selon le type d\'activité.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN 12599 (essais et mesures des systèmes de ventilation)','d':'Norme européenne définissant les méthodes d\'essai et de mesure pour vérifier les performances des installations de ventilation : débits d\'air, pressions, vitesses, étanchéité des réseaux.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN 15804 (déclarations environnementales produits construction)','d':'Norme européenne définissant le cadre et les règles de catégorie pour l\'élaboration des déclarations environnementales de produits de construction (DEP/FDES) basées sur l\'ACV.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN 15978 (évaluation performance environnementale des bâtiments)','d':'Norme européenne définissant la méthode de calcul des impacts environnementaux d\'un bâtiment sur l\'ensemble de son cycle de vie, servant de base à l\'évaluation carbone et ACV en HQE et RE2020.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN 16798-1 (paramètres d\'ambiance intérieure)','d':'Norme européenne définissant les paramètres de l\'environnement intérieur à prendre en compte pour la conception et l\'évaluation de la performance énergétique des bâtiments : température, humidité, ventilation, éclairage, acoustique.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN 16798-3 (ventilation bâtiments non résidentiels)','d':'Norme européenne fixant les exigences de performance des systèmes de ventilation et de conditionnement d\'air des bâtiments non résidentiels : débits d\'air, filtration, qualité de l\'air.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN 17037 (lumière naturelle dans les bâtiments)','d':'Norme européenne définissant les méthodes d\'évaluation de l\'éclairage naturel dans les bâtiments : autonomie en lumière naturelle, exposition au soleil, accès aux vues, protection contre l\'éblouissement.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN 1717 (protection contre la pollution de l\'eau potable)','d':'Norme européenne définissant les dispositifs de protection contre les retours d\'eau dans les réseaux d\'eau potable (disconnecteurs, clapets, surverses) selon le niveau de risque de contamination.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN 206 (béton — spécification, performance, production, conformité)','d':'Norme européenne fixant les exigences pour le béton frais et durci : classes de résistance, durabilité, composition, contrôle de production. Base pour la formulation des bétons bas carbone.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN 50492 (mesure champ électromagnétique in situ)','d':'Norme européenne définissant la méthode de mesure des champs électromagnétiques in situ pour vérifier la conformité aux limites d\'exposition, utilisée dans le thème ONDE de la certification HQE.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN ISO 10052 (mesurage simplifié isolement acoustique)','d':'Norme définissant une méthode simplifiée de mesurage de l\'isolement acoustique des bâtiments, utilisée pour des contrôles rapides ne nécessitant pas la précision de la méthode de référence.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN ISO 16283-1 (mesurage in situ isolement acoustique)','d':'Norme de référence définissant la méthode de mesurage in situ de l\'isolement acoustique aux bruits aériens entre locaux, utilisée pour vérifier la conformité aux exigences acoustiques réglementaires.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN ISO 3382 (temps de réverbération)','d':'Norme définissant la méthode de mesurage du temps de réverbération dans les locaux, paramètre essentiel du confort acoustique lié à l\'intelligibilité de la parole et à l\'ambiance sonore.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN ISO 717-1 (isolement acoustique)','d':'Norme définissant les méthodes de détermination des indices uniques d\'isolement acoustique (Rw, DnT,w) à partir des résultats de mesure en bandes de fréquences, avec les termes d\'adaptation C et Ctr.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF EN ISO 7730 (ambiances thermiques modérées — PMV/PPD)','d':'Norme définissant les méthodes d\'évaluation du confort thermique par les indices PMV (Vote Moyen Prévisible) et PPD (Pourcentage Prévisible d\'Insatisfaits), en fonction de six paramètres (température, humidité, vitesse d\'air, rayonnement, activité, habillement).','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'NF T 90-431 (recherche et dénombrement de Legionella)','d':'Norme française de référence pour la détection et le comptage des bactéries Legionella dans les échantillons d\'eau par culture sur gélose, utilisée dans les analyses réglementaires de prévention du risque légionelles.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'RAGE (Règles de l\'Art Grenelle Environnement)','d':'Ensemble de guides et recommandations professionnels élaborés dans le cadre du programme RAGE pour accompagner la mise en œuvre des technologies et solutions constructives issues du Grenelle de l\'Environnement.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Circulaire DGS n° 2002/273 (légionelles)','d':'Circulaire du ministère de la Santé définissant les mesures de prévention du risque légionelles dans les établissements de santé et les ERP : surveillance, entretien, seuils d\'intervention.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Guide AICVF (ventilation, climatisation)','d':'Publication technique de l\'AICVF fournissant des recommandations pour la conception, le dimensionnement et l\'exploitation des installations de ventilation et de climatisation des bâtiments.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Guide CEREMA — Fiche n° 02 (CPE, avril 2015)','d':'Fiche technique du CEREMA présentant les principes, les conditions de succès et les retours d\'expérience sur les Contrats de Performance Énergétique dans le secteur du bâtiment.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Guide FREDON PACA (produits phytosanitaires, novembre 2017)','d':'Guide régional édité par la FREDON PACA présentant les alternatives aux produits phytosanitaires chimiques pour la gestion écologique des espaces verts, dans le cadre de la démarche « zéro phyto ».','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Guide RAGE (Règles de l\'Art Grenelle Environnement)','d':'Série de guides professionnels publiés sous l\'égide du programme RAGE, fournissant les bonnes pratiques de mise en œuvre des solutions constructives performantes pour les bâtiments BBC et au-delà.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Référentiel Ecocert (gestion espaces verts)','d':'Référentiel de certification Ecocert appliqué à la gestion écologique des espaces verts, définissant les pratiques respectueuses de l\'environnement : absence de pesticides, gestion de l\'eau, biodiversité.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'Référentiel Plantes et Cité (gestion écologique espaces verts)','d':'Label national porté par l\'association Plantes & Cité certifiant la gestion écologique des espaces verts publics et privés, sur la base de critères de biodiversité, d\'absence de pesticides et de gestion de l\'eau.','c':'RÉFÉRENCES RÉGLEMENTAIRES ET NORMATIVES'},{'t':'BREEAM','d':'Building Research Establishment Environmental Assessment Method. Méthode d\'évaluation et de certification environnementale des bâtiments d\'origine britannique, utilisée dans plus de 80 pays, évaluant l\'énergie, la santé, le transport, l\'eau, les matériaux, les déchets, l\'écologie et la gestion.','c':'LABELS ET CERTIFICATIONS'},{'t':'BREEAM In-Use','d':'Déclinaison de la certification BREEAM dédiée aux bâtiments en exploitation, évaluant la performance environnementale du bâtiment existant, sa gestion et l\'expérience des occupants.','c':'LABELS ET CERTIFICATIONS'},{'t':'Certification ISO 14001','d':'Attestation par un organisme accrédité qu\'une organisation a mis en place un système de management environnemental conforme à la norme ISO 14001, démontrant son engagement d\'amélioration continue de sa performance environnementale.','c':'LABELS ET CERTIFICATIONS'},{'t':'Certification ISO 50001','d':'Attestation par un organisme accrédité qu\'une organisation a mis en place un système de management de l\'énergie conforme à la norme ISO 50001, visant l\'amélioration systématique de sa performance énergétique.','c':'LABELS ET CERTIFICATIONS'},{'t':'Certification ISO 9001','d':'Attestation par un organisme accrédité qu\'une organisation a mis en place un système de management de la qualité conforme à la norme ISO 9001, garantissant la satisfaction des clients et l\'amélioration continue des processus.','c':'LABELS ET CERTIFICATIONS'},{'t':'Effinergie','d':'Association française promouvant les bâtiments basse consommation, à l\'origine des labels BBC-Effinergie, Effinergie+ et BEPOS-Effinergie, fixant des niveaux de performance énergétique supérieurs à la réglementation.','c':'LABELS ET CERTIFICATIONS'},{'t':'HQE (Haute Qualité Environnementale)','d':'Démarche française de certification environnementale des bâtiments, portée par l\'Alliance HQE-GBC et délivrée par Certivea (tertiaire) et Cerqual (logement), évaluant la performance sur quatre engagements : énergie, environnement, santé, confort.','c':'LABELS ET CERTIFICATIONS'},{'t':'HQE-B (Bâtiment)','d':'Volet de la certification HQE évaluant les caractéristiques intrinsèques du bâtiment : conception architecturale, performance des systèmes, qualité des matériaux, résultats de mesures in situ.','c':'LABELS ET CERTIFICATIONS'},{'t':'HQE-BD (Bâtiment Durable)','d':'Version actuelle de la certification HQE (v4.1) intégrant les dimensions de durabilité sur l\'ensemble du cycle de vie du bâtiment : conception, réalisation et exploitation, avec les axes Bâtiment et Gestion.','c':'LABELS ET CERTIFICATIONS'},{'t':'Label BBCA (Bâtiment Bas Carbone)','d':'Label valorisant les bâtiments neufs ou rénovés dont l\'empreinte carbone est significativement réduite sur l\'ensemble du cycle de vie, favorisant les matériaux biosourcés, le réemploi et l\'énergie décarbonée.','c':'LABELS ET CERTIFICATIONS'},{'t':'Label BiodiverCity','d':'Label international évaluant la prise en compte de la biodiversité dans les projets immobiliers, selon quatre axes : engagement du maître d\'ouvrage, projet écologique, potentiel écologique du site, bénéfices pour les usagers.','c':'LABELS ET CERTIFICATIONS'},{'t':'Label E+C-','d':'Label expérimental « Énergie Positive et Réduction Carbone » ayant préfiguré la RE2020, évaluant la performance des bâtiments neufs sur deux axes : le bilan énergétique (E1 à E4) et l\'empreinte carbone (C1 à C2).','c':'LABELS ET CERTIFICATIONS'},{'t':'Label R2S (Ready2Services)','d':'Label certifiant la capacité d\'un bâtiment à accueillir des services numériques (GTB, IoT, connectivité, interopérabilité), garantissant une infrastructure réseau adaptée au smart building.','c':'LABELS ET CERTIFICATIONS'},{'t':'Label WiredScore','d':'Certification internationale évaluant la qualité de la connectivité numérique d\'un bâtiment : infrastructure réseau, redondance, résilience et capacité d\'adaptation aux évolutions technologiques.','c':'LABELS ET CERTIFICATIONS'},{'t':'LEED','d':'Leadership in Energy and Environmental Design. Système de certification environnementale des bâtiments d\'origine américaine (USGBC), évaluant les sites durables, l\'efficacité de l\'eau, l\'énergie, les matériaux, la qualité de l\'environnement intérieur et l\'innovation.','c':'LABELS ET CERTIFICATIONS'},{'t':'Minergie','d':'Standard suisse de construction à haute efficacité énergétique, exigeant un confort élevé, une enveloppe performante et un renouvellement d\'air contrôlé, avec des niveaux Minergie, Minergie-P et Minergie-A.','c':'LABELS ET CERTIFICATIONS'},{'t':'NF Environnement','d':'Écolabel officiel français (marque NF), délivré par AFNOR Certification, attestant qu\'un produit présente un impact réduit sur l\'environnement tout en maintenant un niveau de qualité satisfaisant.','c':'LABELS ET CERTIFICATIONS'},{'t':'Nordic Swan','d':'Écolabel officiel des pays nordiques, créé en 1989, certifiant les produits et services respectant des critères environnementaux exigeants sur l\'ensemble de leur cycle de vie, des matières premières à la fin de vie.','c':'LABELS ET CERTIFICATIONS'},{'t':'PassivHaus','d':'Standard allemand de construction passive définissant des critères de performance très exigeants : besoin de chauffage inférieur à 15 kWh/m².an, étanchéité à l\'air n50 < 0,6 vol/h, et consommation d\'énergie primaire inférieure à 120 kWh/m².an.','c':'LABELS ET CERTIFICATIONS'},{'t':'Écolabel européen','d':'Label environnemental officiel de l\'Union européenne (Règlement CE 66/2010), identifiable par le logo « EU Ecolabel » en forme de fleur, certifiant les produits et services respectant des critères environnementaux sur l\'ensemble de leur cycle de vie.','c':'LABELS ET CERTIFICATIONS'},{'t':'BER — Building Emission Rate','d':'Taux d’émissions de CO₂ du bâtiment évalué (kgCO₂/m²/an), calculé à l’aide d’un logiciel de modélisation énergétique agréé. Il traduit la performance réelle du bâtiment tel que conçu et se compare au TER pour vérifier la conformité réglementaire.','c':'BREEAM RFO — ACRONYMES'},{'t':'TER — Target Emission Rate','d':'Taux d’émissions de CO₂ cible (kgCO₂/m²/an) fixé par la réglementation thermique du pays d’évaluation. Le rapport BER/TER (Energy Performance Ratio) détermine le nombre de crédits Ene01.','c':'BREEAM RFO — ACRONYMES'},{'t':'BREEAM Rating','d':'Échelle de notation BREEAM : Pass (≥30%), Good (≥45%), Very Good (≥55%), Excellent (≥70%), Outstanding (≥85%). Chaque niveau impose des exigences minimales obligatoires. Le niveau final est calculé à partir du score pondéré de chaque catégorie.','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'Design Stage','d':'Phase du processus BREEAM couvrant la conception préliminaire (Concept Design), la conception détaillée (Developed Design) et la conception technique (Technical Design). L’évaluation Design Stage est un engagement prévisionnel de conformité fondé sur les documents de conception, avant le démarrage des travaux.','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'Post Construction Stage','d':'Phase au cours de laquelle l’évaluateur vérifie que le bâtiment construit est conforme à l’évaluation Design Stage : inspection sur site, vérification des preuves de mise en œuvre et confirmation de la conformité effective.','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'Coefficient de transmission thermique (U-value)','d':'Coefficient de transmission thermique d’un élément de construction (W/m²·K), représentant le flux de chaleur traversant un mètre carré de paroi pour un écart de température de 1 Kelvin entre ses deux faces. Plus la valeur U est faible, meilleure est l’isolation.','c':'BREEAM RFO — PHYSIQUE DU BÂTIMENT'},{'t':'Pont thermique (Thermal bridging)','d':'Zone localisée de l’enveloppe du bâtiment dont la résistance thermique est nettement inférieure à celle des éléments voisins, provoquant une augmentation locale du flux de chaleur. Exemples : jonctions mur-plancher, linteaux, nez de dalles, fixations traversantes.','c':'BREEAM RFO — PHYSIQUE DU BÂTIMENT'},{'t':'Inertie thermique (Thermal mass)','d':'Capacité d’un matériau ou d’un élément de construction à stocker puis restituer la chaleur. Une inertie thermique élevée (béton, brique, pierre) atténue les variations de température intérieure.','c':'BREEAM RFO — PHYSIQUE DU BÂTIMENT'},{'t':'Perméabilité à l’air (Air tightness)','d':'Mesure du débit de fuite d’air à travers l’enveloppe du bâtiment, exprimée en m³/(h·m²) à 50 Pa (ISO 9972:2015). Un bon niveau d’étanchéité réduit les pertes énergétiques dues aux infiltrations non contrôlées.','c':'BREEAM RFO — PHYSIQUE DU BÂTIMENT'},{'t':'HVAC — Chauffage, Ventilation et Climatisation','d':'Ensemble des systèmes de chauffage, de ventilation et de climatisation d’un bâtiment : chaudières, pompes à chaleur, centrales de traitement d’air (CTA), systèmes de refroidissement, réseaux de distribution et régulation associée.','c':'BREEAM RFO — PHYSIQUE DU BÂTIMENT'},{'t':'Cogénération (CHP)','d':'Système de production simultanée d’électricité et de chaleur à partir d’une même source d’énergie primaire (le plus souvent le gaz naturel). Rendement global supérieur à celui d’une production séparée. Peut être classé comme technologie bas carbone (LZC) sous certaines conditions BREEAM.','c':'BREEAM RFO — PHYSIQUE DU BÂTIMENT'},{'t':'Carbone incorporé (Embodied carbon)','d':'Quantité totale de gaz à effet de serre émise lors de l’extraction, de la fabrication, du transport, de la mise en œuvre et de la fin de vie des matériaux de construction (kgCO₂e). À distinguer du carbone opérationnel, lié à l’exploitation du bâtiment.','c':'BREEAM RFO — PHYSIQUE DU BÂTIMENT'},{'t':'Analyse du Cycle de Vie (ACV)','d':'Méthode normalisée (ISO 14040/14044) d’évaluation des impacts environnementaux d’un produit ou d’un système sur l’ensemble de son cycle de vie : extraction, fabrication, transport, utilisation, fin de vie.','c':'BREEAM RFO — PHYSIQUE DU BÂTIMENT'},{'t':'Green Guide to Specification','d':'Outil en ligne du BRE attribuant des notes environnementales (A+ à E) aux spécifications courantes d’éléments de construction, sur la base de la méthodologie Environmental Profiles (ACV conforme ISO 14040). Utilisé dans Mat01.','c':'BREEAM RFO — MATÉRIAUX ET RESSOURCES'},{'t':'Impact environnemental incorporé (Embodied impact)','d':'Ensemble des impacts environnementaux (au-delà du seul carbone) liés au cycle de vie des matériaux de construction : changement climatique, épuisement des ressources, acidification, eutrophisation, formation d’ozone troposphérique, etc.','c':'BREEAM RFO — MATÉRIAUX ET RESSOURCES'},{'t':'Rafraîchissement passif (Free cooling)','d':'Mode de refroidissement des espaces intérieurs sans recours à une production mécanique de froid. Tire parti des conditions climatiques favorables (air extérieur frais, eau froide souterraine, surventilation nocturne) pour évacuer la chaleur accumulée.','c':'BREEAM RFO — PHYSIQUE DU BÂTIMENT'},{'t':'Évaluateur BREEAM (BREEAM Assessor)','d':'Professionnel agréé par BRE Global pour réaliser les évaluations BREEAM : collecte des preuves, vérification de la conformité et soumission du rapport d’évaluation au BRE en vue de la délivrance du certificat. Agrément maintenu par formation continue (CPD).','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'Niveau exemplaire (Exemplary level)','d':'Niveau de performance dépassant les exigences maximales d’un crédit BREEAM standard. Permet d’obtenir des crédits Innovation (Inn01) supplémentaires, dans la limite de 10 crédits Innovation au total.','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'Crédit d’innovation (Innovation credit)','d':'Crédit attribué via Inn01 pour une performance exemplaire dans un crédit standard ou pour une innovation approuvée par BRE Global. Maximum 10 crédits, chacun valant 1% du score BREEAM total.','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'Exigences minimales (Minimum standards)','d':'Critères obligatoires à satisfaire pour chaque niveau de certification BREEAM. Un bâtiment ne peut obtenir un niveau donné (Good, Very Good, Excellent, Outstanding) sans les respecter, même si le score total est suffisant.','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'Mise en service (Commissioning)','d':'Processus systématique de vérification attestant que tous les systèmes du bâtiment (CVC, éclairage, régulation, enveloppe) sont installés, réglés et fonctionnent conformément aux spécifications de conception et aux besoins des occupants.','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'Mise en service saisonnière (Seasonal commissioning)','d':'Prolongement de la mise en service initiale sur une période couvrant les différentes saisons (en général 12 mois), pour vérifier et optimiser les performances des systèmes sous différentes conditions climatiques.','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'Livraison (Handover)','d':'Processus de transfert formel du bâtiment achevé, du constructeur au maître d’ouvrage ou à l’occupant : documentation technique, formation des utilisateurs, guides d’utilisation, informations de maintenance.','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'Prérequis (Pre-requisite)','d':'Critères ou crédits à satisfaire obligatoirement pour atteindre un niveau de certification BREEAM donné. Synonyme d’exigences minimales dans le contexte BREEAM.','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'Lux (lx)','d':'Unité SI d’éclairement lumineux, équivalant à un lumen par mètre carré. Un bureau courant requiert de 300 à 500 lux sur le plan de travail.','c':'BREEAM RFO — TERMES SECTORIELS'},{'t':'TEWI — Total Equivalent Warming Impact','d':'Impact global d’un système frigorifique sur le réchauffement climatique, combinant les émissions directes (fuites de fluide frigorigène × PRG) et les émissions indirectes (consommation énergétique × facteur d’émission CO₂) sur la durée de vie de l’équipement.','c':'BREEAM RFO — TERMES SECTORIELS'},{'t':'EPC — Energy Performance Certificate','d':'Certificat de performance énergétique obligatoire lors de la construction, vente ou location d’un bâtiment, classant celui-ci de A (le plus performant) à G (le moins performant).','c':'BREEAM RFO — TERMES SECTORIELS'},{'t':'DEC — Display Energy Certificate','d':'Certificat d’affichage énergétique requis pour les bâtiments publics de plus de 250 m², fondé sur la consommation énergétique réelle mesurée (non calculée). Actualisé chaque année.','c':'BREEAM RFO — TERMES SECTORIELS'},{'t':'NCM — National Calculation Method','d':'Méthode nationale de calcul de la performance énergétique des bâtiments, servant à démontrer la conformité à la directive EPBD.','c':'BREEAM RFO — TERMES SECTORIELS'},{'t':'SBEM — Simplified Building Energy Model','d':'Logiciel de calcul simplifié de la performance énergétique des bâtiments non résidentiels, conforme au NCM. Alternative aux logiciels de simulation thermique dynamique pour les bâtiments de géométrie simple.','c':'BREEAM RFO — TERMES SECTORIELS'},{'t':'DSM — Dynamic Simulation Model','d':'Logiciel de modélisation thermique dynamique permettant la simulation horaire des flux thermiques, de la consommation énergétique et du confort thermique. Exemples : IES VE, DesignBuilder, TAS.','c':'BREEAM RFO — TERMES SECTORIELS'},{'t':'SuDS — Systèmes de drainage durable','d':'Dispositifs de gestion des eaux pluviales de surface reproduisant le drainage naturel. Comprennent : bassins d’infiltration, noues, chaussées perméables, toitures végétalisées, récupération d’eaux pluviales.','c':'BREEAM RFO — TERMES SECTORIELS'},{'t':'EPD — Déclaration environnementale de produit','d':'Document conforme à l’ISO 14025 (Type III) fournissant des données quantifiées et vérifiées par un organisme tiers sur les impacts environnementaux d’un produit tout au long de son cycle de vie.','c':'BREEAM RFO — MATÉRIAUX ET RESSOURCES'},{'t':'RSM — Approvisionnement responsable en matériaux','d':'Démarche d’approvisionnement responsable en matériaux de construction, attestée par des schémas de certification tiers évalués par BRE Global. Voir Mat03 et la note d’orientation GN18.','c':'BREEAM RFO — MATÉRIAUX ET RESSOURCES'},{'t':'RMP — Plan de gestion des ressources','d':'Plan de gestion des ressources du chantier de construction, combinant la réduction des déchets, le tri, le réemploi et le recyclage. Défini dans Wst01.','c':'BREEAM RFO — MATÉRIAUX ET RESSOURCES'},{'t':'POE — Évaluation post-occupation','d':'Processus systématique d’évaluation de la performance d’un bâtiment en conditions réelles d’exploitation, généralement 12 mois après l’occupation. Couvre la performance énergétique, le confort et la satisfaction des usagers.','c':'BREEAM RFO — PROCESSUS ET ÉVALUATION'},{'t':'CIBSE — Chartered Institution of Building Services Engineers','d':'Institution professionnelle britannique des ingénieurs en équipements techniques du bâtiment. Publie des guides de référence (TM, AM, Lighting Guides) largement utilisés à l’échelle internationale.','c':'BREEAM RFO — ORGANISMES'},{'t':'BRE — Building Research Establishment','d':'Organisme de recherche britannique spécialisé dans la construction et l’environnement bâti. BRE Global, sa filiale de certification, administre le référentiel BREEAM, délivre les certificats et accrédite les évaluateurs.','c':'BREEAM RFO — ORGANISMES'},{'t':'UKAS — United Kingdom Accreditation Service','d':'Service national d’accréditation du Royaume-Uni, chargé de l’évaluation et de l’accréditation des organismes de certification, d’inspection et d’essai. Référencé dans Hea05 et Man04.','c':'BREEAM RFO — ORGANISMES'},{'t':'BS 5837:2012','d':'Arbres : prise en compte dans la conception, la démolition et la construction. Référencé dans LE02.','c':'BREEAM RFO — NORMES BS'},{'t':'BS 8206','d':'Code de bonnes pratiques pour l’éclairage naturel (Partie 2). Référencé dans Hea01.','c':'BREEAM RFO — NORMES BS'},{'t':'BS 8542:2011','d':'Conception en vue de l’efficacité d’utilisation des matériaux dans les projets de construction. Référencé dans Wat01.','c':'BREEAM RFO — NORMES BS'},{'t':'BS 8895','d':'Conception en vue de l’efficacité d’utilisation des matériaux dans les projets de construction. Référencé dans Mat06.','c':'BREEAM RFO — NORMES BS'},{'t':'EN 200:2008','d':'Robinetterie sanitaire : robinets simples et mitigeurs pour les systèmes d’alimentation en eau. Référencé dans Wat01.','c':'BREEAM RFO — NORMES EN'},{'t':'EN 717-1:2004','d':'Panneaux à base de bois : détermination du dégagement de formaldéhyde. Référencé dans Hea02.','c':'BREEAM RFO — NORMES EN'},{'t':'EN 1112:2008','d':'Robinetterie sanitaire : pommes de douche pour les systèmes d’alimentation en eau. Référencé dans Wat01.','c':'BREEAM RFO — NORMES EN'},{'t':'EN 12464-1','d':'Lumière et éclairage : éclairage des lieux de travail intérieurs. Référencé dans Hea01.','c':'BREEAM RFO — NORMES EN'},{'t':'EN 12469:2000','d':'Postes de sécurité microbiologique : installation et utilisation. Référencé dans Hea03.','c':'BREEAM RFO — NORMES EN'},{'t':'EN 13201','d':'Éclairage public. Référencé dans Hea01.','c':'BREEAM RFO — NORMES EN'},{'t':'EN 13779:2007','d':'Ventilation des bâtiments : exigences de performance des systèmes de ventilation et de conditionnement d’air. Référencé dans Hea02.','c':'BREEAM RFO — NORMES EN'},{'t':'EN 14175','d':'Sorbonnes : confinement et recommandations d’utilisation. Référencé dans Hea03.','c':'BREEAM RFO — NORMES EN'},{'t':'EN 15221-1:2006','d':'Facility management : termes et définitions. Référencé dans Man01.','c':'BREEAM RFO — NORMES EN'},{'t':'EN 15804','d':'Produits de construction : déclarations environnementales de produit (DEP) — Règles de base. Référencé dans Mat01.','c':'BREEAM RFO — NORMES EN'},{'t':'EN 378-1:2008','d':'Systèmes frigorifiques et pompes à chaleur : exigences de sécurité et d’environnement. Référencé dans Pol01.','c':'BREEAM RFO — NORMES EN'},{'t':'EN ISO 7730:2005','d':'Ergonomie des ambiances thermiques : détermination du confort thermique par les indices PMV et PPD. Référencé dans Hea04.','c':'BREEAM RFO — NORMES EN ISO'},{'t':'EN ISO 11890-2:2013','d':'Peintures et vernis : émissions de composés organiques volatils (Partie 2). Référencé dans Hea02.','c':'BREEAM RFO — NORMES EN ISO'},{'t':'EN ISO 14025:2010','d':'Étiquettes et déclarations environnementales : déclarations de Type III (DEP). Référencé dans Mat01.','c':'BREEAM RFO — NORMES EN ISO'},{'t':'EN ISO 14644-7:2004','d':'Salles propres et environnements maîtrisés : dispositifs séparatifs (Partie 7). Référencé dans Hea03.','c':'BREEAM RFO — NORMES EN ISO'},{'t':'EN ISO 16000-9:2006','d':'Air intérieur : dosage des émissions de COV des produits de construction et d’ameublement. Référencé dans Hea02.','c':'BREEAM RFO — NORMES EN ISO'},{'t':'ISO 140-4:1998','d':'Acoustique : mesurage de l’isolement acoustique des immeubles et des éléments de construction. Référencé dans Hea05.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 354:2003','d':'Acoustique : mesurage du coefficient d’absorption acoustique en salle réverbérante. Référencé dans Hea05.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 717-1:1996','d':'Acoustique : évaluation de l’isolement acoustique des immeubles et des éléments de construction. Référencé dans Hea05.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 5149:2014','d':'Sécurité des systèmes frigorifiques (ammoniac). Référencé dans Pol01.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 6781-3:2015','d':'Isolation thermique : thermographie des bâtiments et des systèmes (Partie 3). Référencé dans Man04.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 9972:2015','d':'Performance thermique des bâtiments : détermination de la perméabilité à l’air. Référencé dans Man04.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 14001','d':'Systèmes de management environnemental : exigences et lignes directrices pour leur utilisation. Référencé dans Man03.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 14040','d':'Analyse du Cycle de Vie : principes et cadre. Norme fondamentale pour les EPD et l’évaluation des impacts des matériaux. Référencé dans Mat01.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 14044','d':'Analyse du Cycle de Vie : exigences et lignes directrices. Complète l’ISO 14040. Référencé dans Mat01.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 15189:2012','d':'Laboratoires de biologie médicale : exigences de qualité et de compétence. Référencé dans Hea03.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 15686-5:2008','d':'Bâtiments et ouvrages construits : prévision de la durée de vie — Partie 5 : coût global. Référencé dans Man02.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 16283-1:2014','d':'Acoustique : mesurage in situ de l’isolement acoustique des bâtiments (Partie 1). Référencé dans Hea05.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 17024','d':'Évaluation de la conformité : exigences générales pour les organismes de certification de personnes. Référencé dans Man04.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 18436-7:2014','d':'Surveillance et diagnostic des machines : exigences de qualification — Partie 7 : thermographie. Référencé dans Man04.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 21930','d':'Déclaration environnementale des produits de construction. Référencé dans Mat01.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 25745-1','d':'Ascenseurs : performance énergétique des machines de traction (Partie 1). Référencé dans Ene06.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 1996-2:2007','d':'Acoustique : description, mesurage et évaluation du bruit de l’environnement. Référencé dans Pol05.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 14020:2001','d':'Étiquettes et déclarations environnementales : principes généraux. Référencé dans Mat01.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 14021','d':'Étiquettes et déclarations environnementales : autodéclarations environnementales (Type II). Référencé dans Mat01.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 14024','d':'Étiquettes et déclarations environnementales : étiquetage de Type I. Référencé dans Mat01.','c':'BREEAM RFO — NORMES ISO'},{'t':'ISO 14025','d':'Étiquettes et déclarations environnementales : déclarations de Type III. Référencé dans Mat01.','c':'BREEAM RFO — NORMES ISO'},{'t':'CIBSE Lighting Guide 10','d':'Éclairage naturel et conception des fenêtres. Référencé dans Hea01.','c':'BREEAM RFO — PUBLICATIONS CIBSE'},{'t':'CIBSE TM39','d':'Comptage de l’énergie dans les bâtiments. Référencé dans Ene02.','c':'BREEAM RFO — PUBLICATIONS CIBSE'},{'t':'CIBSE TM46','d':'Valeurs de référence de consommation énergétique. Référencé dans Man05 et Ene07.','c':'BREEAM RFO — PUBLICATIONS CIBSE'},{'t':'CIBSE TM47','d':'Indicateurs de performance opérationnelle et certificats d’affichage énergétique. Référencé dans Man05.','c':'BREEAM RFO — PUBLICATIONS CIBSE'},{'t':'CIBSE TM50','d':'Évaluation du confort thermique. Référencé dans Ene08.','c':'BREEAM RFO — PUBLICATIONS CIBSE'},{'t':'CIBSE TM54','d':'Évaluation de la performance énergétique réelle des bâtiments dès la phase de conception. Référencé dans Man05 et Ene01.','c':'BREEAM RFO — PUBLICATIONS CIBSE'},{'t':'SD225','d':'Manuel technique BREEAM International RFO 2015 V1.4 — Document source principal du référentiel.','c':'BREEAM RFO — DOCUMENTS BRE'},{'t':'GN18','d':'Note d’orientation BREEAM n°18 : schémas de certification d’approvisionnement responsable. Référencé dans Mat03.','c':'BREEAM RFO — DOCUMENTS BRE'},{'t':'HTM 08-01','d':'Mémorandum technique de santé (NHS) relatif à l’acoustique. Référencé dans Hea05.','c':'BREEAM RFO — RÉGLEMENTATION UK'},{'t':'ECA — Enhanced Capital Allowance','d':'Dispositif britannique d’allègement fiscal pour les investissements dans les équipements à haute efficacité énergétique, associé à la liste ETPL (Energy Technology Product List). Référencé dans Ene05 et Pol01.','c':'BREEAM RFO — RÉGLEMENTATION UK'},{'t':'Directive 2004/42/CE','d':'Directive « Peintures » : limitation de la teneur en COV des peintures et vernis décoratifs. Référencé dans Hea02.','c':'BREEAM RFO — DIRECTIVES EUROPÉENNES'},{'t':'Directive 2009/28/CE','d':'Directive sur les énergies renouvelables. Référencé dans Ene01 et Ene04.','c':'BREEAM RFO — DIRECTIVES EUROPÉENNES'},{'t':'EPBD — Directive performance énergétique des bâtiments','d':'Directive européenne sur la performance énergétique des bâtiments (Energy Performance of Buildings Directive). Référencé dans Ene01.','c':'BREEAM RFO — DIRECTIVES EUROPÉENNES'},{'t':'Protocole de Montréal','d':'Protocole international relatif aux substances appauvrissant la couche d’ozone. Référencé dans Pol01.','c':'BREEAM RFO — PROTOCOLES INTERNATIONAUX'},{'t':'EMAS — Système de management environnemental et d’audit','d':'Système communautaire de management environnemental et d’audit (Eco-Management and Audit Scheme). Référencé dans Man03.','c':'BREEAM RFO — ORGANISMES'},{'t':'WRAP — Programme d’action déchets et ressources','d':'Organisme britannique (Waste & Resources Action Programme) promouvant l’économie circulaire et la réduction des déchets de construction. Référencé dans Mat06 et Wst01.','c':'BREEAM RFO — ORGANISMES'},{'t':'BSRIA — Building Services Research and Information Association','d':'Association britannique de recherche et d’information sur les services du bâtiment. Référencé dans Man05.','c':'BREEAM RFO — ORGANISMES'},{'t':'BCO — British Council for Offices','d':'Organisme professionnel britannique pour les immeubles de bureaux. Auteur du guide de l’évaluation post-occupation (2007). Référencé dans Man05.','c':'BREEAM RFO — ORGANISMES'},{'t':'CITES — Convention sur le commerce des espèces menacées','d':'Convention sur le commerce international des espèces de faune et de flore sauvages menacées d’extinction. Référencé dans Mat03.','c':'BREEAM RFO — ORGANISMES'},{'t':'UNEP — Programme des Nations Unies pour l’environnement','d':'Organisme des Nations Unies. Auteur du rapport sur les fluides frigorigènes (2010). Référencé dans Pol01.','c':'BREEAM RFO — ORGANISMES'}];
